use crate::format::Sample;

/// Interleaved audio buffer with channel-based access.
///
/// Stores samples interleaved (L R L R ...) for cache locality,
/// but provides per-channel slice access for processing.
#[derive(Debug, Clone)]
pub struct AudioBuffer {
    data: Vec<Sample>,
    channels: u16,
    frames: u32,
}

impl AudioBuffer {
    /// Create a new zero-filled buffer.
    pub fn new(channels: u16, frames: u32) -> Self {
        Self {
            data: vec![0.0; channels as usize * frames as usize],
            channels,
            frames,
        }
    }

    /// Create a buffer from existing interleaved sample data.
    pub fn from_interleaved(data: Vec<Sample>, channels: u16) -> Self {
        let frames = data.len() as u32 / channels as u32;
        Self {
            data,
            channels,
            frames,
        }
    }

    pub fn channels(&self) -> u16 {
        self.channels
    }

    pub fn frames(&self) -> u32 {
        self.frames
    }

    pub fn sample_count(&self) -> usize {
        self.data.len()
    }

    /// Get a single sample at (frame, channel).
    pub fn get(&self, frame: u32, channel: u16) -> Sample {
        self.data[frame as usize * self.channels as usize + channel as usize]
    }

    /// Set a single sample at (frame, channel).
    pub fn set(&mut self, frame: u32, channel: u16, value: Sample) {
        self.data[frame as usize * self.channels as usize + channel as usize] = value;
    }

    /// Access the raw interleaved data.
    pub fn as_interleaved(&self) -> &[Sample] {
        &self.data
    }

    /// Access the raw interleaved data mutably.
    pub fn as_interleaved_mut(&mut self) -> &mut [Sample] {
        &mut self.data
    }

    /// Copy samples for a single channel into the provided slice.
    pub fn read_channel(&self, channel: u16, out: &mut [Sample]) {
        let ch = channel as usize;
        let stride = self.channels as usize;
        for (i, sample) in out.iter_mut().enumerate() {
            *sample = self.data[i * stride + ch];
        }
    }

    /// Write samples for a single channel from the provided slice.
    pub fn write_channel(&mut self, channel: u16, src: &[Sample]) {
        let ch = channel as usize;
        let stride = self.channels as usize;
        for (i, &sample) in src.iter().enumerate() {
            self.data[i * stride + ch] = sample;
        }
    }

    /// Fill the entire buffer with silence.
    pub fn clear(&mut self) {
        self.data.fill(0.0);
    }

    /// Mix (add) another buffer's contents into this one.
    pub fn mix_from(&mut self, other: &AudioBuffer) {
        assert_eq!(self.channels, other.channels);
        let len = self.data.len().min(other.data.len());
        for i in 0..len {
            self.data[i] += other.data[i];
        }
    }

    /// Apply gain to the entire buffer.
    pub fn apply_gain(&mut self, gain: Sample) {
        for sample in &mut self.data {
            *sample *= gain;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_new_buffer_is_silent() {
        let buf = AudioBuffer::new(2, 128);
        assert!(buf.as_interleaved().iter().all(|&s| s == 0.0));
    }

    #[test]
    fn test_get_set() {
        let mut buf = AudioBuffer::new(2, 4);
        buf.set(1, 0, 0.5);
        buf.set(1, 1, -0.5);
        assert_eq!(buf.get(1, 0), 0.5);
        assert_eq!(buf.get(1, 1), -0.5);
        assert_eq!(buf.get(0, 0), 0.0);
    }

    #[test]
    fn test_channel_read_write() {
        let mut buf = AudioBuffer::new(2, 4);
        let left = [0.1, 0.2, 0.3, 0.4];
        buf.write_channel(0, &left);

        let mut out = [0.0; 4];
        buf.read_channel(0, &mut out);
        assert_eq!(out, left);

        // Right channel should still be silent
        buf.read_channel(1, &mut out);
        assert_eq!(out, [0.0; 4]);
    }

    #[test]
    fn test_mix_from() {
        let mut a = AudioBuffer::from_interleaved(vec![0.5, 0.5, 0.5, 0.5], 2);
        let b = AudioBuffer::from_interleaved(vec![0.3, 0.3, 0.3, 0.3], 2);
        a.mix_from(&b);
        for &s in a.as_interleaved() {
            assert!((s - 0.8).abs() < 1e-6);
        }
    }

    #[test]
    fn test_apply_gain() {
        let mut buf = AudioBuffer::from_interleaved(vec![1.0, -1.0, 0.5, -0.5], 2);
        buf.apply_gain(0.5);
        assert_eq!(buf.as_interleaved(), &[0.5, -0.5, 0.25, -0.25]);
    }
}

use crate::buffer::AudioBuffer;
use crate::format::Sample;

/// Dynamic range compressor with adjustable threshold, ratio, attack, and release.
#[derive(Debug, Clone)]
pub struct Compressor {
    /// Threshold in dB (signals above this are compressed).
    pub threshold_db: f32,
    /// Compression ratio (e.g., 4.0 means 4:1).
    pub ratio: f32,
    /// Attack time in seconds.
    pub attack: f32,
    /// Release time in seconds.
    pub release: f32,
    /// Makeup gain in dB.
    pub makeup_db: f32,
    /// Knee width in dB (0 = hard knee).
    pub knee_db: f32,
    sample_rate: f32,
    /// Envelope follower state (linear).
    envelope: f32,
}

impl Compressor {
    pub fn new(sample_rate: f32) -> Self {
        Self {
            threshold_db: -20.0,
            ratio: 4.0,
            attack: 0.01,
            release: 0.1,
            makeup_db: 0.0,
            knee_db: 6.0,
            sample_rate,
            envelope: 0.0,
        }
    }

    pub fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
    }

    /// Compute gain reduction in dB for a given input level in dB.
    fn compute_gain_db(&self, input_db: f32) -> f32 {
        let half_knee = self.knee_db / 2.0;
        let over = input_db - self.threshold_db;

        if self.knee_db > 0.0 && over.abs() < half_knee {
            // Soft knee region
            let x = over + half_knee;
            let compressed = self.threshold_db + x - x * x / (2.0 * self.knee_db)
                + (x * x / (2.0 * self.knee_db)) / self.ratio;
            compressed - input_db
        } else if over <= -half_knee {
            // Below threshold
            0.0
        } else {
            // Above threshold
            (self.threshold_db + over / self.ratio) - input_db
        }
    }

    /// Process an audio buffer in place.
    pub fn process(&mut self, buffer: &mut AudioBuffer) {
        let channels = buffer.channels() as usize;
        let frames = buffer.frames();
        let attack_coeff = (-1.0 / (self.attack * self.sample_rate)).exp();
        let release_coeff = (-1.0 / (self.release * self.sample_rate)).exp();
        let makeup_linear = db_to_linear(self.makeup_db);

        for frame in 0..frames {
            // Detect peak across channels
            let mut peak: f32 = 0.0;
            for ch in 0..channels {
                peak = peak.max(buffer.get(frame, ch as u16).abs());
            }

            // Envelope follower
            let coeff = if peak > self.envelope {
                attack_coeff
            } else {
                release_coeff
            };
            self.envelope = coeff * self.envelope + (1.0 - coeff) * peak;

            // Compute gain reduction
            let env_db = linear_to_db(self.envelope);
            let gain_db = self.compute_gain_db(env_db);
            let gain = db_to_linear(gain_db) * makeup_linear;

            // Apply gain
            for ch in 0..channels {
                let sample = buffer.get(frame, ch as u16) * gain;
                buffer.set(frame, ch as u16, sample);
            }
        }
    }

    /// Reset envelope state.
    pub fn reset(&mut self) {
        self.envelope = 0.0;
    }
}

fn linear_to_db(linear: f32) -> f32 {
    if linear < 1e-10 {
        -200.0
    } else {
        20.0 * linear.log10()
    }
}

fn db_to_linear(db: f32) -> Sample {
    10.0_f32.powf(db / 20.0)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_compressor_below_threshold() {
        let mut comp = Compressor::new(48000.0);
        comp.threshold_db = 0.0;
        comp.ratio = 4.0;
        comp.makeup_db = 0.0;
        comp.knee_db = 0.0;

        // Quiet signal should pass through mostly unchanged
        let data: Vec<f32> = (0..256).map(|_| 0.01).collect();
        let mut buf = AudioBuffer::from_interleaved(data, 1);
        comp.process(&mut buf);

        for i in 10..256 {
            let sample = buf.get(i, 0);
            assert!((sample - 0.01).abs() < 0.005, "frame {i}: {sample}");
        }
    }

    #[test]
    fn test_compressor_reduces_loud_signal() {
        let mut comp = Compressor::new(48000.0);
        comp.threshold_db = -20.0;
        comp.ratio = 10.0;
        comp.attack = 0.001;
        comp.release = 0.01;
        comp.makeup_db = 0.0;
        comp.knee_db = 0.0;

        // Loud signal (0 dBFS)
        let frames = 4800;
        let data: Vec<f32> = (0..frames)
            .map(|i| (2.0 * std::f32::consts::PI * 440.0 * i as f32 / 48000.0).sin())
            .collect();
        let peak_before = data.iter().map(|s| s.abs()).fold(0.0_f32, f32::max);

        let mut buf = AudioBuffer::from_interleaved(data, 1);
        comp.process(&mut buf);

        // After compression, peak should be lower
        let peak_after = (0..frames)
            .map(|i| buf.get(i as u32, 0).abs())
            .fold(0.0_f32, f32::max);

        assert!(
            peak_after < peak_before,
            "Compressed peak {peak_after} should be less than original {peak_before}"
        );
    }

    #[test]
    fn test_db_conversion_roundtrip() {
        let db = -6.0_f32;
        let linear = db_to_linear(db);
        let back = linear_to_db(linear);
        assert!((back - db).abs() < 0.001);
    }
}

use crate::buffer::AudioBuffer;
use crate::format::Sample;

/// Stereo delay effect with feedback and dry/wet mix.
#[derive(Debug, Clone)]
pub struct Delay {
    /// Delay time in seconds.
    pub time: f32,
    /// Feedback amount (0.0 to <1.0).
    pub feedback: f32,
    /// Dry/wet mix (0.0 = fully dry, 1.0 = fully wet).
    pub mix: f32,
    sample_rate: f32,
    // Per-channel circular buffers
    buffers: Vec<Vec<Sample>>,
    write_pos: usize,
}

impl Delay {
    pub fn new(sample_rate: f32) -> Self {
        let max_delay_samples = (sample_rate * 5.0) as usize; // Up to 5 seconds
        Self {
            time: 0.25,
            feedback: 0.4,
            mix: 0.3,
            sample_rate,
            buffers: vec![vec![0.0; max_delay_samples]; 2],
            write_pos: 0,
        }
    }

    pub fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
        let max_delay_samples = (sample_rate * 5.0) as usize;
        self.buffers = vec![vec![0.0; max_delay_samples]; 2];
        self.write_pos = 0;
    }

    fn delay_samples(&self) -> usize {
        (self.time * self.sample_rate) as usize
    }

    /// Process an audio buffer in place.
    pub fn process(&mut self, buffer: &mut AudioBuffer) {
        let channels = buffer.channels() as usize;
        let frames = buffer.frames();
        let delay_samples = self.delay_samples();
        let buf_len = self.buffers[0].len();

        if delay_samples == 0 || buf_len == 0 {
            return;
        }

        for frame in 0..frames {
            for ch in 0..channels.min(2) {
                let input = buffer.get(frame, ch as u16);

                // Read from delay line
                let read_pos = (self.write_pos + buf_len - delay_samples) % buf_len;
                let delayed = self.buffers[ch][read_pos];

                // Write input + feedback to delay line
                self.buffers[ch][self.write_pos] = input + delayed * self.feedback;

                // Mix
                let output = input * (1.0 - self.mix) + delayed * self.mix;
                buffer.set(frame, ch as u16, output);
            }
            self.write_pos = (self.write_pos + 1) % buf_len;
        }
    }

    /// Reset all delay buffers.
    pub fn reset(&mut self) {
        for buf in &mut self.buffers {
            buf.fill(0.0);
        }
        self.write_pos = 0;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_delay_produces_echo() {
        let mut delay = Delay::new(48000.0);
        delay.time = 0.01; // 10ms = 480 samples
        delay.feedback = 0.0;
        delay.mix = 1.0;

        // Impulse at frame 0
        let frames = 960;
        let mut data = vec![0.0_f32; frames];
        data[0] = 1.0;

        let mut buf = AudioBuffer::from_interleaved(data, 1);
        delay.process(&mut buf);

        // The impulse should appear at frame 480 (10ms later)
        assert!(
            buf.get(480, 0).abs() > 0.5,
            "Echo should appear at delay time"
        );
        // Original frame should be near 0 (fully wet, no dry)
        assert!(
            buf.get(0, 0).abs() < 0.01,
            "Dry signal suppressed at mix=1.0"
        );
    }

    #[test]
    fn test_delay_dry_passthrough() {
        let mut delay = Delay::new(48000.0);
        delay.mix = 0.0;

        let mut buf = AudioBuffer::from_interleaved(vec![0.5, -0.5, 0.3, -0.3], 2);
        delay.process(&mut buf);

        assert_eq!(buf.get(0, 0), 0.5);
        assert_eq!(buf.get(0, 1), -0.5);
    }
}

use crate::buffer::AudioBuffer;
use crate::format::Sample;

/// Filter type for a single EQ band.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum FilterType {
    LowShelf,
    HighShelf,
    Peak,
    LowPass,
    HighPass,
}

/// A single EQ band with biquad filter coefficients.
#[derive(Debug, Clone)]
pub struct EqBand {
    pub filter_type: FilterType,
    pub frequency: f32,
    pub gain_db: f32,
    pub q: f32,
    pub enabled: bool,
    // Biquad coefficients
    b0: f64,
    b1: f64,
    b2: f64,
    a1: f64,
    a2: f64,
    // Per-channel state (up to 2 channels)
    state: [[f64; 2]; 2],
}

impl EqBand {
    pub fn new(filter_type: FilterType, frequency: f32, gain_db: f32, q: f32) -> Self {
        let mut band = Self {
            filter_type,
            frequency,
            gain_db,
            q,
            enabled: true,
            b0: 1.0,
            b1: 0.0,
            b2: 0.0,
            a1: 0.0,
            a2: 0.0,
            state: [[0.0; 2]; 2],
        };
        band.compute_coefficients(48000.0);
        band
    }

    /// Recompute biquad coefficients for the given sample rate.
    pub fn compute_coefficients(&mut self, sample_rate: f32) {
        let w0 = 2.0 * std::f64::consts::PI * self.frequency as f64 / sample_rate as f64;
        let cos_w0 = w0.cos();
        let sin_w0 = w0.sin();
        let alpha = sin_w0 / (2.0 * self.q as f64);
        let a = 10.0_f64.powf(self.gain_db as f64 / 40.0);

        let (b0, b1, b2, a0, a1, a2) = match self.filter_type {
            FilterType::Peak => {
                let b0 = 1.0 + alpha * a;
                let b1 = -2.0 * cos_w0;
                let b2 = 1.0 - alpha * a;
                let a0 = 1.0 + alpha / a;
                let a1 = -2.0 * cos_w0;
                let a2 = 1.0 - alpha / a;
                (b0, b1, b2, a0, a1, a2)
            }
            FilterType::LowShelf => {
                let two_sqrt_a_alpha = 2.0 * a.sqrt() * alpha;
                let b0 = a * ((a + 1.0) - (a - 1.0) * cos_w0 + two_sqrt_a_alpha);
                let b1 = 2.0 * a * ((a - 1.0) - (a + 1.0) * cos_w0);
                let b2 = a * ((a + 1.0) - (a - 1.0) * cos_w0 - two_sqrt_a_alpha);
                let a0 = (a + 1.0) + (a - 1.0) * cos_w0 + two_sqrt_a_alpha;
                let a1 = -2.0 * ((a - 1.0) + (a + 1.0) * cos_w0);
                let a2 = (a + 1.0) + (a - 1.0) * cos_w0 - two_sqrt_a_alpha;
                (b0, b1, b2, a0, a1, a2)
            }
            FilterType::HighShelf => {
                let two_sqrt_a_alpha = 2.0 * a.sqrt() * alpha;
                let b0 = a * ((a + 1.0) + (a - 1.0) * cos_w0 + two_sqrt_a_alpha);
                let b1 = -2.0 * a * ((a - 1.0) + (a + 1.0) * cos_w0);
                let b2 = a * ((a + 1.0) + (a - 1.0) * cos_w0 - two_sqrt_a_alpha);
                let a0 = (a + 1.0) - (a - 1.0) * cos_w0 + two_sqrt_a_alpha;
                let a1 = 2.0 * ((a - 1.0) - (a + 1.0) * cos_w0);
                let a2 = (a + 1.0) - (a - 1.0) * cos_w0 - two_sqrt_a_alpha;
                (b0, b1, b2, a0, a1, a2)
            }
            FilterType::LowPass => {
                let b0 = (1.0 - cos_w0) / 2.0;
                let b1 = 1.0 - cos_w0;
                let b2 = (1.0 - cos_w0) / 2.0;
                let a0 = 1.0 + alpha;
                let a1 = -2.0 * cos_w0;
                let a2 = 1.0 - alpha;
                (b0, b1, b2, a0, a1, a2)
            }
            FilterType::HighPass => {
                let b0 = (1.0 + cos_w0) / 2.0;
                let b1 = -(1.0 + cos_w0);
                let b2 = (1.0 + cos_w0) / 2.0;
                let a0 = 1.0 + alpha;
                let a1 = -2.0 * cos_w0;
                let a2 = 1.0 - alpha;
                (b0, b1, b2, a0, a1, a2)
            }
        };

        self.b0 = b0 / a0;
        self.b1 = b1 / a0;
        self.b2 = b2 / a0;
        self.a1 = a1 / a0;
        self.a2 = a2 / a0;
    }

    /// Process a single sample on the given channel. Direct Form II Transposed.
    fn process_sample(&mut self, input: f64, channel: usize) -> f64 {
        let output = self.b0 * input + self.state[channel][0];
        self.state[channel][0] = self.b1 * input - self.a1 * output + self.state[channel][1];
        self.state[channel][1] = self.b2 * input - self.a2 * output;
        output
    }

    /// Reset filter state.
    pub fn reset(&mut self) {
        self.state = [[0.0; 2]; 2];
    }
}

/// Multi-band parametric equalizer.
#[derive(Debug, Clone)]
pub struct ParametricEq {
    pub bands: Vec<EqBand>,
    sample_rate: f32,
}

impl ParametricEq {
    pub fn new(sample_rate: f32) -> Self {
        Self {
            bands: Vec::new(),
            sample_rate,
        }
    }

    /// Add a band and recompute its coefficients.
    pub fn add_band(&mut self, mut band: EqBand) {
        band.compute_coefficients(self.sample_rate);
        self.bands.push(band);
    }

    /// Update sample rate and recompute all coefficients.
    pub fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
        for band in &mut self.bands {
            band.compute_coefficients(sample_rate);
        }
    }

    /// Process an audio buffer in place.
    pub fn process(&mut self, buffer: &mut AudioBuffer) {
        let channels = buffer.channels() as usize;
        let frames = buffer.frames();

        for frame in 0..frames {
            for ch in 0..channels.min(2) {
                let mut sample = buffer.get(frame, ch as u16) as f64;
                for band in &mut self.bands {
                    if band.enabled {
                        sample = band.process_sample(sample, ch);
                    }
                }
                buffer.set(frame, ch as u16, sample as Sample);
            }
        }
    }

    /// Reset all band states.
    pub fn reset(&mut self) {
        for band in &mut self.bands {
            band.reset();
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_eq_passthrough() {
        // A peak band with 0 dB gain should pass through unchanged
        let mut eq = ParametricEq::new(48000.0);
        eq.add_band(EqBand::new(FilterType::Peak, 1000.0, 0.0, 1.0));

        let mut buf = AudioBuffer::from_interleaved(vec![0.5, -0.5, 0.3, -0.3], 2);
        eq.process(&mut buf);

        // With 0 dB gain, output should be very close to input
        assert!((buf.get(0, 0) - 0.5).abs() < 0.01);
        assert!((buf.get(0, 1) + 0.5).abs() < 0.01);
    }

    #[test]
    fn test_eq_boost() {
        let mut eq = ParametricEq::new(48000.0);
        eq.add_band(EqBand::new(FilterType::Peak, 1000.0, 12.0, 1.0));

        // Generate a 1kHz sine at 48kHz, stereo
        let frames = 4800;
        let mut data = vec![0.0_f32; frames * 2];
        for i in 0..frames {
            let val = (2.0 * std::f32::consts::PI * 1000.0 * i as f32 / 48000.0).sin() * 0.5;
            data[i * 2] = val;
            data[i * 2 + 1] = val;
        }
        let mut buf = AudioBuffer::from_interleaved(data, 2);

        // Measure RMS before
        let rms_before: f32 = (0..frames)
            .map(|i| buf.get(i as u32, 0).powi(2))
            .sum::<f32>()
            / frames as f32;

        eq.process(&mut buf);

        // Measure RMS after — should be louder with 12dB boost at 1kHz
        let rms_after: f32 = (0..frames)
            .map(|i| buf.get(i as u32, 0).powi(2))
            .sum::<f32>()
            / frames as f32;

        assert!(
            rms_after > rms_before * 2.0,
            "12dB boost should increase level"
        );
    }

    #[test]
    fn test_disabled_band_passthrough() {
        let mut eq = ParametricEq::new(48000.0);
        let mut band = EqBand::new(FilterType::Peak, 1000.0, 12.0, 1.0);
        band.enabled = false;
        eq.add_band(band);

        let mut buf = AudioBuffer::from_interleaved(vec![0.5, -0.5, 0.3, -0.3], 2);
        eq.process(&mut buf);

        assert_eq!(buf.get(0, 0), 0.5);
        assert_eq!(buf.get(0, 1), -0.5);
    }
}

use crate::buffer::AudioBuffer;

/// Brickwall limiter — prevents signal from exceeding the ceiling.
///
/// Uses a fast-attack, slow-release envelope to smoothly limit peaks.
#[derive(Debug, Clone)]
pub struct Limiter {
    /// Ceiling in dB (maximum output level).
    pub ceiling_db: f32,
    /// Release time in seconds.
    pub release: f32,
    sample_rate: f32,
    envelope: f32,
}

impl Limiter {
    pub fn new(sample_rate: f32) -> Self {
        Self {
            ceiling_db: -0.3,
            release: 0.1,
            sample_rate,
            envelope: 1.0,
        }
    }

    pub fn set_sample_rate(&mut self, sample_rate: f32) {
        self.sample_rate = sample_rate;
    }

    /// Process an audio buffer in place.
    pub fn process(&mut self, buffer: &mut AudioBuffer) {
        let channels = buffer.channels() as usize;
        let frames = buffer.frames();
        let ceiling = 10.0_f32.powf(self.ceiling_db / 20.0);
        let release_coeff = (-1.0 / (self.release * self.sample_rate)).exp();

        for frame in 0..frames {
            // Detect peak across channels
            let mut peak: f32 = 0.0;
            for ch in 0..channels {
                peak = peak.max(buffer.get(frame, ch as u16).abs());
            }

            // Compute required gain reduction
            let target = if peak > ceiling { ceiling / peak } else { 1.0 };

            // Envelope: instant attack, smooth release
            if target < self.envelope {
                self.envelope = target;
            } else {
                self.envelope = release_coeff * self.envelope + (1.0 - release_coeff) * target;
            }

            // Apply gain
            for ch in 0..channels {
                let sample = buffer.get(frame, ch as u16) * self.envelope;
                buffer.set(frame, ch as u16, sample);
            }
        }
    }

    /// Reset state.
    pub fn reset(&mut self) {
        self.envelope = 1.0;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_limiter_caps_output() {
        let mut limiter = Limiter::new(48000.0);
        limiter.ceiling_db = -6.0; // ~0.5 linear
        limiter.release = 0.001;

        let ceiling_linear = 10.0_f32.powf(-6.0 / 20.0);

        // Loud signal
        let frames = 2400;
        let data: Vec<f32> = (0..frames)
            .map(|i| (2.0 * std::f32::consts::PI * 440.0 * i as f32 / 48000.0).sin())
            .collect();

        let mut buf = AudioBuffer::from_interleaved(data, 1);
        limiter.process(&mut buf);

        // After settling, peaks should not exceed ceiling
        for i in 480..frames {
            let sample = buf.get(i as u32, 0).abs();
            assert!(
                sample <= ceiling_linear + 0.05,
                "frame {i}: {sample} exceeds ceiling {ceiling_linear}"
            );
        }
    }

    #[test]
    fn test_limiter_quiet_passthrough() {
        let mut limiter = Limiter::new(48000.0);
        limiter.ceiling_db = 0.0;

        // Signal well below ceiling
        let data = vec![0.1_f32; 256];
        let mut buf = AudioBuffer::from_interleaved(data, 1);
        limiter.process(&mut buf);

        // Should pass through with minimal change (envelope settling)
        for i in 10..256 {
            assert!((buf.get(i, 0) - 0.1).abs() < 0.05);
        }
    }
}

