use std::fmt;

/// Errors that can occur in audio processing.
#[derive(Debug)]
pub enum AudioError {
    /// File I/O error.
    Io(std::io::Error),
    /// Audio format not supported.
    UnsupportedFormat(String),
    /// Audio decoding failed.
    DecodingError(String),
    /// Export error.
    ExportError(String),
    /// Buffer size mismatch.
    BufferMismatch { expected: usize, got: usize },
}

impl fmt::Display for AudioError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            AudioError::Io(e) => write!(f, "I/O error: {e}"),
            AudioError::UnsupportedFormat(fmt_name) => write!(f, "unsupported format: {fmt_name}"),
            AudioError::DecodingError(msg) => write!(f, "decoding error: {msg}"),
            AudioError::ExportError(msg) => write!(f, "export error: {msg}"),
            AudioError::BufferMismatch { expected, got } => {
                write!(f, "buffer size mismatch: expected {expected}, got {got}")
            }
        }
    }
}

impl std::error::Error for AudioError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            AudioError::Io(e) => Some(e),
            _ => None,
        }
    }
}

impl From<std::io::Error> for AudioError {
    fn from(e: std::io::Error) -> Self {
        AudioError::Io(e)
    }
}

/// Audio sample type (32-bit float, range -1.0 to 1.0).
pub type Sample = f32;

/// Describes the format of an audio stream or buffer.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AudioFormat {
    pub sample_rate: u32,
    pub channels: u16,
    pub buffer_size: u32,
}

impl AudioFormat {
    pub fn new(sample_rate: u32, channels: u16, buffer_size: u32) -> Self {
        Self {
            sample_rate,
            channels,
            buffer_size,
        }
    }

    /// Duration of one buffer in seconds.
    pub fn buffer_duration_secs(&self) -> f64 {
        self.buffer_size as f64 / self.sample_rate as f64
    }

    /// Duration of one buffer in milliseconds.
    pub fn buffer_duration_ms(&self) -> f64 {
        self.buffer_duration_secs() * 1000.0
    }
}

impl Default for AudioFormat {
    fn default() -> Self {
        Self {
            sample_rate: 48000,
            channels: 2,
            buffer_size: 256,
        }
    }
}

