    }
}

use std::collections::HashMap;
use std::path::Path;

use shruti_dsp::AudioBuffer;
use shruti_dsp::io::read_audio_file;

/// In-memory pool of audio files loaded into the session.
///
/// Audio files are loaded once and referenced by ID from regions.
/// The pool owns the decoded audio data.
pub struct AudioPool {
    buffers: HashMap<String, AudioBuffer>,
}

impl AudioPool {
    pub fn new() -> Self {
        Self {
            buffers: HashMap::new(),
        }
    }

    /// Insert a pre-decoded buffer into the pool.
    pub fn insert(&mut self, id: String, buffer: AudioBuffer) {
        self.buffers.insert(id, buffer);
    }

    /// Load an audio file from disk and add it to the pool.
    /// Returns the assigned file ID.
    pub fn load(&mut self, path: &Path) -> Result<String, Box<dyn std::error::Error>> {
        let id = path
            .file_name()
            .and_then(|n| n.to_str())
            .unwrap_or("unknown")
            .to_string();

        let (buffer, _format) = read_audio_file(path)?;
        self.buffers.insert(id.clone(), buffer);
        Ok(id)
    }

    /// Get a buffer by ID.
    pub fn get(&self, id: &str) -> Option<&AudioBuffer> {
        self.buffers.get(id)
    }

    /// Remove a buffer by ID.
    pub fn remove(&mut self, id: &str) -> Option<AudioBuffer> {
        self.buffers.remove(id)
    }

    /// List all file IDs in the pool.
    pub fn ids(&self) -> Vec<&str> {
        self.buffers.keys().map(|s| s.as_str()).collect()
    }

    pub fn len(&self) -> usize {
        self.buffers.len()
    }

    pub fn is_empty(&self) -> bool {
        self.buffers.is_empty()
    }
}

impl Default for AudioPool {
    fn default() -> Self {
        Self::new()
    }
}

use serde::{Deserialize, Serialize};

/// Identifies a parameter target for automation.
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum AutomationTarget {
    /// Track volume (linear gain).
    TrackGain,
    /// Track pan (-1.0 to 1.0).
    TrackPan,
    /// Plugin parameter by index.
    PluginParam { slot: usize, param_id: u32 },
    /// Send level by send index.
    SendLevel { send_index: usize },
}

/// Interpolation curve between two automation points.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum CurveType {
    /// Linear interpolation.
    Linear,
    /// Step (hold previous value until next point).
    Step,
    /// Smooth S-curve.
    SCurve,
}

/// A single automation point at a specific timeline position.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AutomationPoint {
    /// Position in frames on the timeline.
    pub position: u64,
    /// Parameter value at this point.
    pub value: f32,
    /// Curve type for interpolation to the next point.
    pub curve: CurveType,
}

/// An automation lane: a sequence of points for a single parameter.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AutomationLane {
    /// What parameter this lane controls.
    pub target: AutomationTarget,
    /// Automation points sorted by position.
    pub points: Vec<AutomationPoint>,
    /// Whether this lane is active.
    pub enabled: bool,
}

impl AutomationLane {
    pub fn new(target: AutomationTarget) -> Self {
        Self {
            target,
            points: Vec::new(),
            enabled: true,
        }
    }

    /// Add a point, maintaining sorted order by position.
    pub fn add_point(&mut self, point: AutomationPoint) {
        let pos = self
            .points
            .binary_search_by_key(&point.position, |p| p.position)
            .unwrap_or_else(|i| i);
        self.points.insert(pos, point);
    }

    /// Remove the point closest to the given position within tolerance.
    pub fn remove_point_near(&mut self, position: u64, tolerance: u64) -> Option<AutomationPoint> {
        if let Some(idx) = self
            .points
            .iter()
            .position(|p| p.position.abs_diff(position) <= tolerance)
        {
            Some(self.points.remove(idx))
        } else {
            None
        }
    }

    /// Get the interpolated value at a given timeline position.
    pub fn value_at(&self, position: u64) -> Option<f32> {
        if self.points.is_empty() {
            return None;
        }

        // Before first point
        if position <= self.points[0].position {
            return Some(self.points[0].value);
        }

        // After last point
        if position >= self.points.last().unwrap().position {
            return Some(self.points.last().unwrap().value);
        }

        // Find surrounding points
        let right_idx = self
            .points
            .binary_search_by_key(&position, |p| p.position)
            .unwrap_or_else(|i| i);

        if right_idx == 0 {
            return Some(self.points[0].value);
        }

        let left = &self.points[right_idx - 1];
        let right = &self.points[right_idx];

        let t = (position - left.position) as f32 / (right.position - left.position) as f32;

        let value = match left.curve {
            CurveType::Linear => left.value + (right.value - left.value) * t,
            CurveType::Step => left.value,
            CurveType::SCurve => {
                // Hermite-style smooth step
                let t2 = t * t * (3.0 - 2.0 * t);
                left.value + (right.value - left.value) * t2
            }
        };

        Some(value)
    }

    /// Get all points in a range.
    pub fn points_in_range(&self, start: u64, end: u64) -> &[AutomationPoint] {
        let start_idx = self
            .points
            .binary_search_by_key(&start, |p| p.position)
            .unwrap_or_else(|i| i);
        let end_idx = self
            .points
            .binary_search_by_key(&end, |p| p.position)
            .unwrap_or_else(|i| i);
        &self.points[start_idx..end_idx]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_automation_lane_add_sorted() {
        let mut lane = AutomationLane::new(AutomationTarget::TrackGain);
        lane.add_point(AutomationPoint {
            position: 100,
            value: 0.5,
            curve: CurveType::Linear,
        });
        lane.add_point(AutomationPoint {
            position: 50,
            value: 0.0,
            curve: CurveType::Linear,
        });
        lane.add_point(AutomationPoint {
            position: 200,
            value: 1.0,
            curve: CurveType::Linear,
        });

        assert_eq!(lane.points[0].position, 50);
        assert_eq!(lane.points[1].position, 100);
        assert_eq!(lane.points[2].position, 200);
    }

    #[test]
    fn test_linear_interpolation() {
        let mut lane = AutomationLane::new(AutomationTarget::TrackGain);
        lane.add_point(AutomationPoint {
            position: 0,
            value: 0.0,
            curve: CurveType::Linear,
        });
        lane.add_point(AutomationPoint {
            position: 100,
            value: 1.0,
            curve: CurveType::Linear,
        });

        assert!((lane.value_at(0).unwrap() - 0.0).abs() < 0.001);
        assert!((lane.value_at(50).unwrap() - 0.5).abs() < 0.001);
        assert!((lane.value_at(100).unwrap() - 1.0).abs() < 0.001);
    }

    #[test]
    fn test_step_interpolation() {
        let mut lane = AutomationLane::new(AutomationTarget::TrackPan);
        lane.add_point(AutomationPoint {
            position: 0,
            value: -1.0,
            curve: CurveType::Step,
        });
        lane.add_point(AutomationPoint {
            position: 100,
            value: 1.0,
            curve: CurveType::Step,
        });

        assert_eq!(lane.value_at(0).unwrap(), -1.0);
        assert_eq!(lane.value_at(50).unwrap(), -1.0);
        assert_eq!(lane.value_at(99).unwrap(), -1.0);
        assert_eq!(lane.value_at(100).unwrap(), 1.0);
    }

    #[test]
    fn test_scurve_interpolation() {
        let mut lane = AutomationLane::new(AutomationTarget::TrackGain);
        lane.add_point(AutomationPoint {
            position: 0,
            value: 0.0,
            curve: CurveType::SCurve,
        });
        lane.add_point(AutomationPoint {
            position: 100,
            value: 1.0,
            curve: CurveType::SCurve,
        });

        let mid = lane.value_at(50).unwrap();
        // S-curve at midpoint should be 0.5
        assert!((mid - 0.5).abs() < 0.01);

        // S-curve should start slow and end slow
        let early = lane.value_at(10).unwrap();
        let late = lane.value_at(90).unwrap();
        // The slope at the edges should be gentler than linear
        assert!(early < 0.1 + 0.01); // Should be < linear (0.1)
        assert!(late > 0.9 - 0.01); // Should be > linear (0.9)
    }

    #[test]
    fn test_value_outside_range() {
        let mut lane = AutomationLane::new(AutomationTarget::TrackGain);
        lane.add_point(AutomationPoint {
            position: 100,
            value: 0.5,
            curve: CurveType::Linear,
        });
        lane.add_point(AutomationPoint {
            position: 200,
            value: 1.0,
            curve: CurveType::Linear,
        });

        // Before first point — hold first value
        assert_eq!(lane.value_at(0).unwrap(), 0.5);
        // After last point — hold last value
        assert_eq!(lane.value_at(300).unwrap(), 1.0);
    }

    #[test]
    fn test_empty_lane() {
        let lane = AutomationLane::new(AutomationTarget::TrackGain);
        assert!(lane.value_at(50).is_none());
    }

    #[test]
    fn test_remove_point() {
        let mut lane = AutomationLane::new(AutomationTarget::TrackGain);
        lane.add_point(AutomationPoint {
            position: 100,
            value: 0.5,
            curve: CurveType::Linear,
        });

        assert!(lane.remove_point_near(105, 10).is_some());
        assert!(lane.points.is_empty());
    }
}

use serde::{Deserialize, Serialize};

use crate::region::{Region, RegionId};
use crate::track::TrackId;

/// An editing command that can be applied and undone.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum EditCommand {
    /// Add a region to a track.
    AddRegion { track_id: TrackId, region: Region },
    /// Remove a region from a track.
    RemoveRegion {
        track_id: TrackId,
        region_id: RegionId,
        /// The removed region, stored for undo.
        region: Option<Region>,
    },
    /// Move a region to a new timeline position.
    MoveRegion {
        track_id: TrackId,
        region_id: RegionId,
        old_pos: u64,
        new_pos: u64,
    },
    /// Move a region from one track to another.
    MoveRegionToTrack {
        from_track: TrackId,
        to_track: TrackId,
        region_id: RegionId,
        old_pos: u64,
        new_pos: u64,
        /// Stored for undo.
        region: Option<Region>,
    },
    /// Split a region at a frame position, replacing it with two new regions.
    SplitRegion {
        track_id: TrackId,
        region_id: RegionId,
        split_frame: u64,
        /// The original region before split, stored for undo.
        original: Option<Region>,
        /// The two resulting regions after split.
        left_id: Option<RegionId>,
        right_id: Option<RegionId>,
    },
    /// Trim the start of a region.
    TrimStart {
        track_id: TrackId,
        region_id: RegionId,
        old_start: u64,
        old_offset: u64,
        old_duration: u64,
        new_start: u64,
    },
    /// Trim the end of a region.
    TrimEnd {
        track_id: TrackId,
        region_id: RegionId,
        old_duration: u64,
        new_end: u64,
    },
    /// Set fade-in duration on a region.
    SetFadeIn {
        track_id: TrackId,
        region_id: RegionId,
        old_fade: u64,
        new_fade: u64,
    },
    /// Set fade-out duration on a region.
    SetFadeOut {
        track_id: TrackId,
        region_id: RegionId,
        old_fade: u64,
        new_fade: u64,
    },
    /// Set region gain.
    SetRegionGain {
        track_id: TrackId,
        region_id: RegionId,
        old_gain: f32,
        new_gain: f32,
    },
    /// Set track gain.
    SetTrackGain {
        track_id: TrackId,
        old_gain: f32,
        new_gain: f32,
    },
    /// Set track pan.
    SetTrackPan {
        track_id: TrackId,
        old_pan: f32,
        new_pan: f32,
    },
    /// Toggle track mute.
    ToggleTrackMute { track_id: TrackId },
    /// Toggle track solo.
    ToggleTrackSolo { track_id: TrackId },
    /// Compound command (multiple edits as one undoable action).
    Compound { commands: Vec<EditCommand> },
}

use std::fmt;

/// Errors that can occur in session management.
#[derive(Debug)]
pub enum SessionError {
    /// File I/O error.
    Io(std::io::Error),
    /// Database error.
    Database(String),
    /// Serialization/deserialization error.
    Serialization(String),
    /// Track not found.
    TrackNotFound(String),
    /// Region not found.
    RegionNotFound(String),
    /// Invalid operation.
    InvalidOperation(String),
    /// Audio processing error.
    Audio(String),
}

impl fmt::Display for SessionError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            SessionError::Io(e) => write!(f, "I/O error: {e}"),
            SessionError::Database(msg) => write!(f, "database error: {msg}"),
            SessionError::Serialization(msg) => write!(f, "serialization error: {msg}"),
            SessionError::TrackNotFound(name) => write!(f, "track not found: {name}"),
            SessionError::RegionNotFound(id) => write!(f, "region not found: {id}"),
            SessionError::InvalidOperation(msg) => write!(f, "invalid operation: {msg}"),
            SessionError::Audio(msg) => write!(f, "audio error: {msg}"),
        }
    }
}

impl std::error::Error for SessionError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            SessionError::Io(e) => Some(e),
            _ => None,
        }
    }
}

impl From<std::io::Error> for SessionError {
    fn from(e: std::io::Error) -> Self {
        SessionError::Io(e)
    }
}

impl From<rusqlite::Error> for SessionError {
    fn from(e: rusqlite::Error) -> Self {
        SessionError::Database(e.to_string())
    }
}

impl From<serde_json::Error> for SessionError {
    fn from(e: serde_json::Error) -> Self {
        SessionError::Serialization(e.to_string())
    }
}

