use serde::{Deserialize, Serialize};

/// Transport playback state.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum TransportState {
    Stopped,
    Playing,
    Paused,
    Recording,
}

/// Transport controls: playback position, tempo, time signature, loop region.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Transport {
    pub state: TransportState,
    /// Current playback position in frames (sample-accurate).
    pub position: u64,
    /// Tempo in BPM.
    pub bpm: f64,
    /// Time signature numerator (e.g. 4 in 4/4).
    pub time_sig_num: u8,
    /// Time signature denominator (e.g. 4 in 4/4).
    pub time_sig_den: u8,
    /// Sample rate of the session.
    pub sample_rate: u32,
    /// Loop enabled.
    pub loop_enabled: bool,
    /// Loop start position in frames.
    pub loop_start: u64,
    /// Loop end position in frames.
    pub loop_end: u64,
}

impl Transport {
    pub fn new(sample_rate: u32) -> Self {
        Self {
            state: TransportState::Stopped,
            position: 0,
            bpm: 120.0,
            time_sig_num: 4,
            time_sig_den: 4,
            sample_rate,
            loop_enabled: false,
            loop_start: 0,
            loop_end: 0,
        }
    }

    pub fn play(&mut self) {
        self.state = TransportState::Playing;
    }

    pub fn stop(&mut self) {
        self.state = TransportState::Stopped;
        self.position = 0;
    }

    pub fn pause(&mut self) {
        self.state = TransportState::Stopped;
    }

    pub fn seek(&mut self, position: u64) {
        self.position = position;
    }

    /// Advance the transport by `frames` and return the actual range processed,
    /// handling loop boundaries.
    pub fn advance(&mut self, frames: u32) -> (u64, u64) {
        let start = self.position;

        if self.loop_enabled && self.loop_end > self.loop_start {
            let end = start + frames as u64;
            if end >= self.loop_end {
                self.position = self.loop_start + (end - self.loop_end);
            } else {
                self.position = end;
            }
        } else {
            self.position += frames as u64;
        }

        (start, self.position)
    }

    /// Convert a frame position to seconds.
    pub fn frames_to_secs(&self, frames: u64) -> f64 {
        frames as f64 / self.sample_rate as f64
    }

    /// Convert seconds to frame position.
    pub fn secs_to_frames(&self, secs: f64) -> u64 {
        (secs * self.sample_rate as f64) as u64
    }

    /// Convert a frame position to beats.
    pub fn frames_to_beats(&self, frames: u64) -> f64 {
        let secs = self.frames_to_secs(frames);
        secs * self.bpm / 60.0
    }

    /// Convert beats to frame position.
    pub fn beats_to_frames(&self, beats: f64) -> u64 {
        let secs = beats * 60.0 / self.bpm;
        self.secs_to_frames(secs)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_transport_advance() {
        let mut t = Transport::new(48000);
        t.play();
        let (start, end) = t.advance(256);
        assert_eq!(start, 0);
        assert_eq!(end, 256);
        assert_eq!(t.position, 256);
    }

    #[test]
    fn test_transport_loop() {
        let mut t = Transport::new(48000);
        t.loop_enabled = true;
        t.loop_start = 0;
        t.loop_end = 1000;
        t.position = 900;
        t.play();

        let (start, _end) = t.advance(256);
        assert_eq!(start, 900);
        // 900 + 256 = 1156, wraps to 1156 - 1000 = 156
        assert_eq!(t.position, 156);
    }

    #[test]
    fn test_time_conversions() {
        let t = Transport::new(48000);
        assert_eq!(t.frames_to_secs(48000), 1.0);
        assert_eq!(t.secs_to_frames(1.0), 48000);

        // At 120 BPM: 1 beat = 0.5 seconds = 24000 frames
        assert!((t.frames_to_beats(24000) - 1.0).abs() < 1e-10);
        assert_eq!(t.beats_to_frames(1.0), 24000);
    }
}

use crate::edit::EditCommand;
use crate::session::Session;

/// Manages undo/redo history using the command pattern.
pub struct UndoManager {
    undo_stack: Vec<EditCommand>,
    redo_stack: Vec<EditCommand>,
    max_history: usize,
}

impl UndoManager {
    pub fn new(max_history: usize) -> Self {
        Self {
            undo_stack: Vec::new(),
            redo_stack: Vec::new(),
            max_history,
        }
    }

    /// Execute a command, pushing it onto the undo stack.
    pub fn execute(&mut self, mut cmd: EditCommand, session: &mut Session) {
        apply_command(&mut cmd, session);
        self.undo_stack.push(cmd);
        self.redo_stack.clear();

        if self.undo_stack.len() > self.max_history {
            self.undo_stack.remove(0);
        }
    }

    /// Undo the last command.
    pub fn undo(&mut self, session: &mut Session) -> bool {
        if let Some(cmd) = self.undo_stack.pop() {
            reverse_command(&cmd, session);
            self.redo_stack.push(cmd);
            true
        } else {
            false
        }
    }

    /// Redo the last undone command.
    pub fn redo(&mut self, session: &mut Session) -> bool {
        if let Some(mut cmd) = self.redo_stack.pop() {
            apply_command(&mut cmd, session);
            self.undo_stack.push(cmd);
            true
        } else {
            false
        }
    }

    pub fn can_undo(&self) -> bool {
        !self.undo_stack.is_empty()
    }

    pub fn can_redo(&self) -> bool {
        !self.redo_stack.is_empty()
    }

    pub fn undo_count(&self) -> usize {
        self.undo_stack.len()
    }

    pub fn redo_count(&self) -> usize {
        self.redo_stack.len()
    }

    pub fn clear(&mut self) {
        self.undo_stack.clear();
        self.redo_stack.clear();
    }
}

impl Default for UndoManager {
    fn default() -> Self {
        Self::new(1000)
    }
}

fn apply_command(cmd: &mut EditCommand, session: &mut Session) {
    match cmd {
        EditCommand::AddRegion { track_id, region } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.add_region(region.clone());
            }
        }
        EditCommand::RemoveRegion {
            track_id,
            region_id,
            region,
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                *region = track.remove_region(*region_id);
            }
        }
        EditCommand::MoveRegion {
            track_id,
            region_id,
            new_pos,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.timeline_pos = *new_pos;
            }
        }
        EditCommand::MoveRegionToTrack {
            from_track,
            to_track,
            region_id,
            new_pos,
            region,
            ..
        } => {
            if let Some(track) = session.track_mut(*from_track) {
                *region = track.remove_region(*region_id);
            }
            if let Some(mut r) = region.clone() {
                r.timeline_pos = *new_pos;
                if let Some(track) = session.track_mut(*to_track) {
                    track.add_region(r);
                }
            }
        }
        EditCommand::SplitRegion {
            track_id,
            region_id,
            split_frame,
            original,
            left_id,
            right_id,
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region(*region_id)
            {
                let r_clone = r.clone();
                if let Some((left, right)) = r_clone.split_at(*split_frame) {
                    *left_id = Some(left.id);
                    *right_id = Some(right.id);
                    *original = track.remove_region(*region_id);
                    track.add_region(left);
                    track.add_region(right);
                }
            }
        }
        EditCommand::TrimStart {
            track_id,
            region_id,
            new_start,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.trim_start(*new_start);
            }
        }
        EditCommand::TrimEnd {
            track_id,
            region_id,
            new_end,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.trim_end(*new_end);
            }
        }
        EditCommand::SetFadeIn {
            track_id,
            region_id,
            new_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_in = *new_fade;
            }
        }
        EditCommand::SetFadeOut {
            track_id,
            region_id,
            new_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_out = *new_fade;
            }
        }
        EditCommand::SetRegionGain {
            track_id,
            region_id,
            new_gain,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.gain = *new_gain;
            }
        }
        EditCommand::SetTrackGain {
            track_id, new_gain, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.gain = *new_gain;
            }
        }
        EditCommand::SetTrackPan {
            track_id, new_pan, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.pan = *new_pan;
            }
        }
        EditCommand::ToggleTrackMute { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.muted = !track.muted;
            }
        }
        EditCommand::ToggleTrackSolo { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.solo = !track.solo;
            }
        }
        EditCommand::Compound { commands } => {
            for sub in commands.iter_mut() {
                apply_command(sub, session);
            }
        }
    }
}

fn reverse_command(cmd: &EditCommand, session: &mut Session) {
    match cmd {
        EditCommand::AddRegion { track_id, region } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.remove_region(region.id);
            }
        }
        EditCommand::RemoveRegion {
            track_id, region, ..
        } => {
            if let Some(r) = region
                && let Some(track) = session.track_mut(*track_id)
            {
                track.add_region(r.clone());
            }
        }
        EditCommand::MoveRegion {
            track_id,
            region_id,
            old_pos,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.timeline_pos = *old_pos;
            }
        }
        EditCommand::MoveRegionToTrack {
            from_track,
            to_track,
            region_id,
            old_pos,
            region,
            ..
        } => {
            if let Some(track) = session.track_mut(*to_track) {
                track.remove_region(*region_id);
            }
            if let Some(mut r) = region.clone() {
                r.timeline_pos = *old_pos;
                if let Some(track) = session.track_mut(*from_track) {
                    track.add_region(r);
                }
            }
        }
        EditCommand::SplitRegion {
            track_id,
            original,
            left_id,
            right_id,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                if let Some(lid) = left_id {
                    track.remove_region(*lid);
                }
                if let Some(rid) = right_id {
                    track.remove_region(*rid);
                }
                if let Some(orig) = original {
                    track.add_region(orig.clone());
                }
            }
        }
        EditCommand::TrimStart {
            track_id,
            region_id,
            old_start,
            old_offset,
            old_duration,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.timeline_pos = *old_start;
                r.source_offset = *old_offset;
                r.duration = *old_duration;
            }
        }
        EditCommand::TrimEnd {
            track_id,
            region_id,
            old_duration,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.duration = *old_duration;
            }
        }
        EditCommand::SetFadeIn {
            track_id,
            region_id,
            old_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_in = *old_fade;
            }
        }
        EditCommand::SetFadeOut {
            track_id,
            region_id,
            old_fade,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.fade_out = *old_fade;
            }
        }
        EditCommand::SetRegionGain {
            track_id,
            region_id,
            old_gain,
            ..
        } => {
            if let Some(track) = session.track_mut(*track_id)
                && let Some(r) = track.region_mut(*region_id)
            {
                r.gain = *old_gain;
            }
        }
        EditCommand::SetTrackGain {
            track_id, old_gain, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.gain = *old_gain;
            }
        }
        EditCommand::SetTrackPan {
            track_id, old_pan, ..
        } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.pan = *old_pan;
            }
        }
        EditCommand::ToggleTrackMute { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.muted = !track.muted;
            }
        }
        EditCommand::ToggleTrackSolo { track_id } => {
            if let Some(track) = session.track_mut(*track_id) {
                track.solo = !track.solo;
            }
        }
        EditCommand::Compound { commands } => {
            for sub in commands.iter().rev() {
                reverse_command(sub, session);
            }
        }
    }
}

use eframe::Frame;
use egui::{CentralPanel, Context, TopBottomPanel};

use crate::input::{Action, ShortcutRegistry, default_keymap};
use crate::state::{UiState, ViewMode};
use crate::theme::{Theme, apply_theme};
use crate::views::{arrangement, browser, mixer, transport};

/// The main Shruti application.
pub struct ShrutiApp {
    state: UiState,
    theme: Theme,
    shortcuts: ShortcutRegistry,
}

impl ShrutiApp {
    pub fn new(state: UiState) -> Self {
        Self {
            state,
            theme: Theme::default(),
            shortcuts: default_keymap(),
        }
    }

    pub fn with_theme(mut self, theme: Theme) -> Self {
        self.theme = theme;
        self
    }

    fn handle_action(&mut self, action: Action) {
        use shruti_session::TransportState;

        match action {
            Action::Play => {
                self.state.session.transport.state = TransportState::Playing;
            }
            Action::Stop => {
                self.state.session.transport.state = TransportState::Stopped;
                self.state.recording = false;
            }
            Action::Pause => {
                self.state.session.transport.state = TransportState::Paused;
            }
            Action::Record => {
                self.state.recording = !self.state.recording;
            }
            Action::ToggleLoop => {
                self.state.session.transport.loop_enabled =
                    !self.state.session.transport.loop_enabled;
            }
            Action::Rewind | Action::GoToStart => {
                self.state.session.transport.position = 0;
            }
            Action::GoToEnd => {
                self.state.session.transport.position = self.state.session.session_length();
            }
            Action::ToggleArrangement => {
                self.state.view_mode = ViewMode::Arrangement;
            }
            Action::ToggleMixer => {
                self.state.view_mode = ViewMode::Mixer;
            }
            Action::ToggleBrowser => {
                self.state.show_browser = !self.state.show_browser;
            }
            Action::ZoomIn => {
                self.state.pixels_per_frame *= 1.3;
            }
            Action::ZoomOut => {
                self.state.pixels_per_frame = (self.state.pixels_per_frame / 1.3).max(0.0001);
            }
            Action::NewAudioTrack => {
                let count = self.state.session.audio_tracks().len() + 1;
                self.state.session.add_audio_track(format!("Audio {count}"));
            }
            Action::ToggleMute => {
                if let Some(idx) = self.state.selected_track
                    && idx < self.state.session.tracks.len()
                {
                    self.state.session.tracks[idx].muted = !self.state.session.tracks[idx].muted;
                }
            }
            Action::ToggleSolo => {
                if let Some(idx) = self.state.selected_track
                    && idx < self.state.session.tracks.len()
                {
                    self.state.session.tracks[idx].solo = !self.state.session.tracks[idx].solo;
                }
            }
            // These actions are recognized but not yet wired
            Action::Undo
            | Action::Redo
            | Action::Cut
            | Action::Copy
            | Action::Paste
            | Action::Delete
            | Action::SelectAll
            | Action::SplitAtPlayhead
            | Action::Duplicate
            | Action::FastForward
            | Action::ZoomToFit
            | Action::NewBusTrack
            | Action::ToggleArm
            | Action::NewSession
            | Action::OpenSession
            | Action::SaveSession
            | Action::ExportAudio => {}
        }
    }
}

impl eframe::App for ShrutiApp {
    fn update(&mut self, ctx: &Context, _frame: &mut Frame) {
        // Apply theme once
        if !self.state.theme_applied {
            apply_theme(ctx, &self.theme.colors);
            self.state.theme_applied = true;
        }

        // Handle keyboard shortcuts
        if let Some(action) = self.shortcuts.check_input(ctx) {
            self.handle_action(action);
        }

        // Handle scroll zoom in arrangement
        if self.state.view_mode == ViewMode::Arrangement {
            ctx.input(|input| {
                if input.modifiers.ctrl {
                    let scroll = input.raw_scroll_delta.y;
                    if scroll != 0.0 {
                        let factor = if scroll > 0.0 { 1.1 } else { 1.0 / 1.1 };
                        self.state.pixels_per_frame =
                            (self.state.pixels_per_frame * factor).clamp(0.00001, 1.0);
                    }
                } else {
                    // Horizontal scroll with shift or trackpad
                    let scroll_x = input.raw_scroll_delta.x - input.raw_scroll_delta.y;
                    self.state.scroll_x = (self.state.scroll_x - scroll_x as f64).max(0.0);
                }
            });
        }

        // Request continuous repaint during playback
        if self.state.session.transport.state == shruti_session::TransportState::Playing {
            ctx.request_repaint();
        }

        let colors = self.theme.colors.clone();

        // Top: Transport bar
        TopBottomPanel::top("transport")
            .min_height(36.0)
            .show(ctx, |ui| {
                transport::transport_bar(ui, &mut self.state, &colors);
            });

        // Bottom: Browser (toggleable)
        if self.state.show_browser {
            TopBottomPanel::bottom("browser")
                .resizable(true)
                .default_height(180.0)
                .min_height(100.0)
                .show(ctx, |ui| {
                    browser::browser_panel(ui, &mut self.state, &colors);
                });
        }

        // Center: Arrangement or Mixer
        CentralPanel::default().show(ctx, |ui| {
            // View switcher bar
            ui.horizontal(|ui| {
                ui.spacing_mut().item_spacing.x = 2.0;

                let arr_selected = self.state.view_mode == ViewMode::Arrangement;
                if ui.selectable_label(arr_selected, "Arrangement").clicked() {
                    self.state.view_mode = ViewMode::Arrangement;
                }
                if ui.selectable_label(!arr_selected, "Mixer").clicked() {
                    self.state.view_mode = ViewMode::Mixer;
                }

                ui.separator();

                // Quick-add track button
                if ui.small_button("+ Track").clicked() {
                    let count = self.state.session.audio_tracks().len() + 1;
                    self.state.session.add_audio_track(format!("Audio {count}"));
                }
            });

            ui.separator();

            match self.state.view_mode {
                ViewMode::Arrangement => {
                    arrangement::arrangement_view(ui, &mut self.state, &colors);
                }
                ViewMode::Mixer => {
                    mixer::mixer_view(ui, &mut self.state, &colors);
                }
            }
        });
    }
}

use egui::Key;

use super::actions::Action;
use super::shortcuts::{Shortcut, ShortcutRegistry};

/// Load the default DAW keybindings (Logic/Reaper hybrid style).
pub fn default_keymap() -> ShortcutRegistry {
    let mut reg = ShortcutRegistry::new();

    // Transport
    reg.bind(Shortcut::key(Key::Space), Action::Play);
    reg.bind(Shortcut::key(Key::Enter), Action::Stop);
    reg.bind(Shortcut::key(Key::R), Action::Record);
    reg.bind(Shortcut::key(Key::L), Action::ToggleLoop);
    reg.bind(Shortcut::key(Key::Home), Action::GoToStart);
    reg.bind(Shortcut::key(Key::End), Action::GoToEnd);

    // Editing
    reg.bind(Shortcut::ctrl(Key::Z), Action::Undo);
    reg.bind(Shortcut::ctrl_shift(Key::Z), Action::Redo);
    reg.bind(Shortcut::ctrl(Key::X), Action::Cut);
    reg.bind(Shortcut::ctrl(Key::C), Action::Copy);
    reg.bind(Shortcut::ctrl(Key::V), Action::Paste);
    reg.bind(Shortcut::key(Key::Delete), Action::Delete);
    reg.bind(Shortcut::key(Key::Backspace), Action::Delete);
    reg.bind(Shortcut::ctrl(Key::A), Action::SelectAll);
    reg.bind(Shortcut::key(Key::S), Action::SplitAtPlayhead);
    reg.bind(Shortcut::ctrl(Key::D), Action::Duplicate);

    // View
    reg.bind(Shortcut::key(Key::F1), Action::ToggleArrangement);
    reg.bind(Shortcut::key(Key::F2), Action::ToggleMixer);
    reg.bind(Shortcut::key(Key::F3), Action::ToggleBrowser);
    reg.bind(Shortcut::ctrl(Key::ArrowUp), Action::ZoomIn);
    reg.bind(Shortcut::ctrl(Key::ArrowDown), Action::ZoomOut);
    reg.bind(Shortcut::ctrl(Key::F), Action::ZoomToFit);

    // Tracks
    reg.bind(Shortcut::ctrl(Key::T), Action::NewAudioTrack);
    reg.bind(Shortcut::key(Key::M), Action::ToggleMute);

    // File
    reg.bind(Shortcut::ctrl(Key::N), Action::NewSession);
    reg.bind(Shortcut::ctrl(Key::O), Action::OpenSession);
    reg.bind(Shortcut::ctrl(Key::S), Action::SaveSession);

    reg
}

