pub mod colors;
pub mod loader;
pub mod style;

pub use colors::ThemeColors;
pub use loader::Theme;
pub use style::apply_theme;

use egui::{Color32, CornerRadius, FontFamily, FontId, Stroke, TextStyle, Visuals, epaint::Shadow};

use super::colors::ThemeColors;

/// Apply the DAW theme to an egui context.
pub fn apply_theme(ctx: &egui::Context, colors: &ThemeColors) {
    let mut visuals = Visuals::dark();

    // Window and panel backgrounds
    visuals.panel_fill = colors.bg_secondary();
    visuals.window_fill = colors.bg_secondary();
    visuals.extreme_bg_color = colors.bg_primary();
    visuals.faint_bg_color = colors.bg_tertiary();
    visuals.code_bg_color = colors.surface();

    // Text colors
    visuals.override_text_color = Some(colors.text_primary());

    // Selection
    visuals.selection.bg_fill = colors.accent().linear_multiply(0.4);
    visuals.selection.stroke = Stroke::new(1.0, colors.accent());

    // Hyperlinks
    visuals.hyperlink_color = colors.accent();

    // Shadows
    visuals.window_shadow = Shadow {
        offset: [0, 4],
        blur: 12,
        spread: 0,
        color: Color32::from_black_alpha(80),
    };
    visuals.popup_shadow = Shadow {
        offset: [0, 2],
        blur: 8,
        spread: 0,
        color: Color32::from_black_alpha(60),
    };

    // Widget styling
    let rounding = CornerRadius::same(4);

    visuals.widgets.noninteractive.bg_fill = colors.surface();
    visuals.widgets.noninteractive.weak_bg_fill = colors.bg_tertiary();
    visuals.widgets.noninteractive.bg_stroke = Stroke::new(0.5, colors.separator());
    visuals.widgets.noninteractive.fg_stroke = Stroke::new(1.0, colors.text_secondary());
    visuals.widgets.noninteractive.corner_radius = rounding;

    visuals.widgets.inactive.bg_fill = colors.surface();
    visuals.widgets.inactive.weak_bg_fill = colors.surface();
    visuals.widgets.inactive.bg_stroke = Stroke::new(0.5, colors.separator());
    visuals.widgets.inactive.fg_stroke = Stroke::new(1.0, colors.text_primary());
    visuals.widgets.inactive.corner_radius = rounding;

    visuals.widgets.hovered.bg_fill = colors.surface_hover();
    visuals.widgets.hovered.weak_bg_fill = colors.surface_hover();
    visuals.widgets.hovered.bg_stroke = Stroke::new(1.0, colors.accent());
    visuals.widgets.hovered.fg_stroke = Stroke::new(1.0, colors.text_primary());
    visuals.widgets.hovered.corner_radius = rounding;

    visuals.widgets.active.bg_fill = colors.accent();
    visuals.widgets.active.weak_bg_fill = colors.accent();
    visuals.widgets.active.bg_stroke = Stroke::new(1.0, colors.accent_hover());
    visuals.widgets.active.fg_stroke = Stroke::new(1.0, Color32::WHITE);
    visuals.widgets.active.corner_radius = rounding;

    visuals.widgets.open.bg_fill = colors.surface_hover();
    visuals.widgets.open.weak_bg_fill = colors.surface_hover();
    visuals.widgets.open.bg_stroke = Stroke::new(1.0, colors.accent());
    visuals.widgets.open.fg_stroke = Stroke::new(1.0, colors.text_primary());
    visuals.widgets.open.corner_radius = rounding;

    ctx.set_visuals(visuals);

    // Font sizes — compact DAW-style
    let mut style = (*ctx.style()).clone();
    style.text_styles = [
        (
            TextStyle::Small,
            FontId::new(10.0, FontFamily::Proportional),
        ),
        (TextStyle::Body, FontId::new(12.0, FontFamily::Proportional)),
        (
            TextStyle::Button,
            FontId::new(12.0, FontFamily::Proportional),
        ),
        (
            TextStyle::Heading,
            FontId::new(14.0, FontFamily::Proportional),
        ),
        (
            TextStyle::Monospace,
            FontId::new(11.0, FontFamily::Monospace),
        ),
    ]
    .into();

    style.spacing.item_spacing = [4.0, 3.0].into();
    style.spacing.button_padding = [6.0, 2.0].into();
    style.spacing.indent = 16.0;

    ctx.set_style(style);
}

use egui::{Rect, ScrollArea, Stroke, Ui, pos2, vec2};

use crate::state::UiState;
use crate::theme::ThemeColors;
use crate::widgets::{region_clip, timeline_ruler, track_header};

const TRACK_HEADER_WIDTH: f32 = 160.0;
const TRACK_HEIGHT: f32 = 60.0;
const RULER_HEIGHT: f32 = 24.0;

/// Draw the arrangement/timeline view.
pub fn arrangement_view(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    // Handle file drops
    let dropped_files: Vec<egui::DroppedFile> = ui.ctx().input(|i| i.raw.dropped_files.clone());
    for file in &dropped_files {
        if let Some(path) = &file.path {
            let path_str = path.display().to_string();
            let ext = path.extension().and_then(|e| e.to_str()).unwrap_or("");
            if matches!(ext, "wav" | "flac" | "aif" | "aiff")
                && !state.file_entries.contains(&path_str)
            {
                state.file_entries.push(path_str);
            }
        }
    }

    let available = ui.available_rect_before_wrap();

    // Ruler at top
    let ruler_rect = Rect::from_min_size(
        pos2(available.left() + TRACK_HEADER_WIDTH, available.top()),
        vec2(available.width() - TRACK_HEADER_WIDTH, RULER_HEIGHT),
    );
    timeline_ruler::draw_ruler(
        ui,
        ruler_rect,
        state.scroll_x,
        state.pixels_per_frame,
        state.session.sample_rate,
        state.session.transport.bpm,
        colors,
    );

    // Content area below ruler
    let content_top = available.top() + RULER_HEIGHT;
    let content_rect = Rect::from_min_max(
        pos2(available.left(), content_top),
        available.right_bottom(),
    );

    let mut content_ui = ui.new_child(egui::UiBuilder::new().max_rect(content_rect));

    ScrollArea::vertical()
        .auto_shrink([false; 2])
        .show(&mut content_ui, |ui| {
            let track_count = state.session.tracks.len();

            for track_idx in 0..track_count {
                ui.horizontal(|ui| {
                    // Track header
                    let track = &state.session.tracks[track_idx];
                    let header_state = track_header::TrackHeaderState {
                        name: track.name.clone(),
                        muted: track.muted,
                        solo: track.solo,
                        armed: track.armed,
                        selected: state.selected_track == Some(track_idx),
                        color_index: track_idx,
                    };

                    let header_resp = track_header::track_header_ui(
                        ui,
                        &header_state,
                        colors,
                        TRACK_HEADER_WIDTH,
                    );

                    if header_resp.selected {
                        state.selected_track = Some(track_idx);
                    }
                    if header_resp.mute_clicked {
                        state.session.tracks[track_idx].muted =
                            !state.session.tracks[track_idx].muted;
                    }
                    if header_resp.solo_clicked {
                        state.session.tracks[track_idx].solo =
                            !state.session.tracks[track_idx].solo;
                    }
                    if header_resp.arm_clicked {
                        state.session.tracks[track_idx].armed =
                            !state.session.tracks[track_idx].armed;
                    }

                    // Timeline lane for this track
                    let lane_width = ui.available_width();
                    let (lane_rect, _) = ui
                        .allocate_exact_size(vec2(lane_width, TRACK_HEIGHT), egui::Sense::click());

                    if ui.is_rect_visible(lane_rect) {
                        let painter = ui.painter_at(lane_rect);

                        // Lane background (alternating)
                        let bg = if track_idx % 2 == 0 {
                            colors.bg_tertiary()
                        } else {
                            colors.bg_secondary()
                        };
                        painter.rect_filled(lane_rect, 0.0, bg);

                        // Bottom separator
                        painter.line_segment(
                            [lane_rect.left_bottom(), lane_rect.right_bottom()],
                            Stroke::new(0.5, colors.separator()),
                        );

                        // Draw grid lines
                        draw_grid(
                            ui,
                            lane_rect,
                            state.scroll_x,
                            state.pixels_per_frame,
                            state.session.sample_rate,
                            state.session.transport.bpm,
                            colors,
                        );

                        // Draw regions
                        let track = &state.session.tracks[track_idx];
                        for region in &track.regions {
                            let region_x = lane_rect.left()
                                + (region.timeline_pos as f64 * state.pixels_per_frame
                                    - state.scroll_x) as f32;
                            let region_w = (region.duration as f64 * state.pixels_per_frame) as f32;

                            if region_x + region_w >= lane_rect.left()
                                && region_x <= lane_rect.right()
                            {
                                let region_rect = Rect::from_min_size(
                                    pos2(region_x.max(lane_rect.left()), lane_rect.top() + 2.0),
                                    vec2(
                                        region_w.min(lane_rect.right() - region_x),
                                        TRACK_HEIGHT - 4.0,
                                    ),
                                );
                                let selected = state.selected_region == Some(region.id);
                                region_clip::draw_region(
                                    ui,
                                    region_rect,
                                    &region.audio_file_id,
                                    track_idx,
                                    selected,
                                    colors,
                                );
                            }
                        }

                        // Draw playhead
                        let playhead_x = lane_rect.left()
                            + (state.session.transport.position as f64 * state.pixels_per_frame
                                - state.scroll_x) as f32;
                        if playhead_x >= lane_rect.left() && playhead_x <= lane_rect.right() {
                            painter.line_segment(
                                [
                                    pos2(playhead_x, lane_rect.top()),
                                    pos2(playhead_x, lane_rect.bottom()),
                                ],
                                Stroke::new(1.0, colors.playhead()),
                            );
                        }
                    }
                });
            }
        });

    // Show drop zone overlay when dragging files
    let is_hovering = ui.ctx().input(|i| !i.raw.hovered_files.is_empty());
    if is_hovering {
        let available = ui.available_rect_before_wrap();
        let painter = ui.painter();
        painter.rect_filled(
            available,
            0.0,
            egui::Color32::from_rgba_premultiplied(100, 150, 255, 30),
        );
        painter.text(
            available.center(),
            egui::Align2::CENTER_CENTER,
            "Drop audio files here",
            egui::FontId::new(18.0, egui::FontFamily::Proportional),
            egui::Color32::from_rgba_premultiplied(200, 220, 255, 180),
        );
    }
}

fn draw_grid(
    ui: &mut Ui,
    rect: Rect,
    scroll_offset: f64,
    pixels_per_frame: f64,
    sample_rate: u32,
    bpm: f64,
    colors: &ThemeColors,
) {
    let painter = ui.painter_at(rect);

    let frames_per_beat = (sample_rate as f64 * 60.0) / bpm;
    let frames_per_bar = frames_per_beat * 4.0;
    let pixels_per_bar = frames_per_bar * pixels_per_frame;

    if pixels_per_bar < 4.0 {
        return;
    }

    let start_frame = (scroll_offset / pixels_per_frame) as i64;
    let end_frame = start_frame + (rect.width() as f64 / pixels_per_frame) as i64;

    let bar_start = (start_frame as f64 / frames_per_bar).floor() as i64;
    let bar_end = (end_frame as f64 / frames_per_bar).ceil() as i64;

    for i in bar_start..=bar_end {
        let frame = (i as f64 * frames_per_bar) as i64;
        let x = rect.left() + (frame as f64 * pixels_per_frame - scroll_offset) as f32;
        if x >= rect.left() && x <= rect.right() {
            painter.line_segment(
                [pos2(x, rect.top()), pos2(x, rect.bottom())],
                Stroke::new(0.5, colors.grid()),
            );
        }

        // Beat subdivision lines if zoomed in enough
        if pixels_per_bar > 80.0 {
            for beat in 1..4 {
                let beat_frame = frame + (beat as f64 * frames_per_beat) as i64;
                let bx =
                    rect.left() + (beat_frame as f64 * pixels_per_frame - scroll_offset) as f32;
                if bx >= rect.left() && bx <= rect.right() {
                    painter.line_segment(
                        [pos2(bx, rect.top()), pos2(bx, rect.bottom())],
                        Stroke::new(0.25, colors.grid()),
                    );
                }
            }
        }
    }
}

use egui::{ScrollArea, Ui};

use crate::state::UiState;
use crate::theme::ThemeColors;

/// Browser panel tab.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BrowserTab {
    Files,
    Plugins,
}

/// Draw the browser panel.
pub fn browser_panel(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    // Handle file drops
    let dropped_files: Vec<egui::DroppedFile> = ui.ctx().input(|i| i.raw.dropped_files.clone());
    for file in &dropped_files {
        if let Some(path) = &file.path {
            let path_str = path.display().to_string();
            let ext = path.extension().and_then(|e| e.to_str()).unwrap_or("");
            if matches!(ext, "wav" | "flac" | "aif" | "aiff")
                && !state.file_entries.contains(&path_str)
            {
                state.file_entries.push(path_str.clone());
            }
        }
    }

    // Tab bar
    ui.horizontal(|ui| {
        if ui
            .selectable_label(state.browser_tab == BrowserTab::Files, "Files")
            .clicked()
        {
            state.browser_tab = BrowserTab::Files;
        }
        if ui
            .selectable_label(state.browser_tab == BrowserTab::Plugins, "Plugins")
            .clicked()
        {
            state.browser_tab = BrowserTab::Plugins;
        }

        // Import button
        ui.with_layout(egui::Layout::right_to_left(egui::Align::Center), |ui| {
            if ui.small_button("Import...").clicked()
                && let Some(path) = rfd::FileDialog::new()
                    .add_filter("Audio", &["wav", "flac", "aif", "aiff"])
                    .pick_file()
            {
                state.file_entries.push(path.display().to_string());
            }
        });
    });

    ui.separator();

    match state.browser_tab {
        BrowserTab::Files => files_tab(ui, state, colors),
        BrowserTab::Plugins => plugins_tab(ui, state, colors),
    }
}

fn files_tab(ui: &mut Ui, state: &UiState, colors: &ThemeColors) {
    ScrollArea::vertical()
        .auto_shrink([false; 2])
        .show(ui, |ui| {
            if state.file_entries.is_empty() {
                ui.label(
                    egui::RichText::new("No files imported yet. Click Import to add audio files.")
                        .size(10.0)
                        .color(colors.text_secondary()),
                );
            } else {
                for entry in &state.file_entries {
                    let filename = entry.rsplit('/').next().unwrap_or(entry);
                    let icon = if entry.ends_with(".wav") {
                        "WAV"
                    } else if entry.ends_with(".flac") {
                        "FLAC"
                    } else {
                        "AIF"
                    };

                    ui.horizontal(|ui| {
                        ui.label(
                            egui::RichText::new(icon)
                                .monospace()
                                .size(8.0)
                                .color(colors.accent()),
                        );
                        ui.label(
                            egui::RichText::new(filename)
                                .size(10.0)
                                .color(colors.text_primary()),
                        );
                    });
                }
            }
        });
}

fn plugins_tab(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    // Search field
    ui.horizontal(|ui| {
        ui.label(
            egui::RichText::new("Search:")
                .size(10.0)
                .color(colors.text_secondary()),
        );
        ui.text_edit_singleline(&mut state.plugin_search);
    });

    ui.add_space(4.0);

    ScrollArea::vertical()
        .auto_shrink([false; 2])
        .show(ui, |ui| {
            if state.plugin_entries.is_empty() {
                ui.label(
                    egui::RichText::new("No plugins found. Use Scan to detect installed plugins.")
                        .size(10.0)
                        .color(colors.text_secondary()),
                );
            } else {
                let search_lower = state.plugin_search.to_lowercase();
                for plugin in &state.plugin_entries {
                    if !search_lower.is_empty()
                        && !plugin.name.to_lowercase().contains(&search_lower)
                    {
                        continue;
                    }

                    ui.horizontal(|ui| {
                        ui.label(
                            egui::RichText::new(&plugin.format)
                                .monospace()
                                .size(8.0)
                                .color(colors.accent()),
                        );
                        ui.label(
                            egui::RichText::new(&plugin.name)
                                .size(10.0)
                                .color(colors.text_primary()),
                        );
                    });
                }
            }
        });
}

use egui::{ScrollArea, Ui, vec2};

use crate::state::UiState;
use crate::theme::ThemeColors;
use crate::widgets::{fader::Fader, knob::Knob, meter::LevelMeter, track_header::track_color};

const STRIP_WIDTH: f32 = 72.0;

/// Draw the mixer view.
pub fn mixer_view(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    ScrollArea::horizontal()
        .auto_shrink([false; 2])
        .show(ui, |ui| {
            ui.horizontal(|ui| {
                let track_count = state.session.tracks.len();

                for track_idx in 0..track_count {
                    channel_strip(ui, state, track_idx, colors);

                    // Separator between strips
                    if track_idx < track_count - 1 {
                        ui.separator();
                    }
                }
            });
        });
}

fn channel_strip(ui: &mut Ui, state: &mut UiState, track_idx: usize, colors: &ThemeColors) {
    ui.vertical(|ui| {
        ui.set_width(STRIP_WIDTH);

        let color = track_color(track_idx);

        // Track name with color indicator
        ui.horizontal(|ui| {
            let (indicator_rect, _) = ui.allocate_exact_size(vec2(4.0, 14.0), egui::Sense::hover());
            if ui.is_rect_visible(indicator_rect) {
                ui.painter_at(indicator_rect)
                    .rect_filled(indicator_rect, 1.0, color);
            }

            let name = &state.session.tracks[track_idx].name;
            ui.label(
                egui::RichText::new(name)
                    .size(10.0)
                    .color(colors.text_primary()),
            );
        });

        ui.add_space(4.0);

        // M S buttons
        ui.horizontal(|ui| {
            ui.spacing_mut().item_spacing.x = 2.0;

            let muted = state.session.tracks[track_idx].muted;
            let mute_color = if muted {
                colors.mute_orange()
            } else {
                colors.surface()
            };
            if ui
                .add(
                    egui::Button::new(egui::RichText::new("M").size(9.0).color(if muted {
                        egui::Color32::WHITE
                    } else {
                        colors.text_secondary()
                    }))
                    .fill(mute_color)
                    .min_size(vec2(18.0, 14.0)),
                )
                .clicked()
            {
                state.session.tracks[track_idx].muted = !muted;
            }

            let solo = state.session.tracks[track_idx].solo;
            let solo_color = if solo {
                colors.solo_yellow()
            } else {
                colors.surface()
            };
            if ui
                .add(
                    egui::Button::new(egui::RichText::new("S").size(9.0).color(if solo {
                        egui::Color32::BLACK
                    } else {
                        colors.text_secondary()
                    }))
                    .fill(solo_color)
                    .min_size(vec2(18.0, 14.0)),
                )
                .clicked()
            {
                state.session.tracks[track_idx].solo = !solo;
            }
        });

        ui.add_space(4.0);

        // Pan knob
        ui.vertical_centered(|ui| {
            let mut pan = state.session.tracks[track_idx].pan;
            ui.add(Knob::pan(&mut pan, colors));
            state.session.tracks[track_idx].pan = pan;
        });

        ui.add_space(4.0);

        // Fader + Meter side by side
        ui.horizontal(|ui| {
            // Fader
            let mut gain = state.session.tracks[track_idx].gain;
            ui.add(Fader::new(&mut gain, colors).height(140.0));
            state.session.tracks[track_idx].gain = gain;

            // Meter
            let meter_data = state
                .meter_levels
                .get(track_idx)
                .copied()
                .unwrap_or(([0.0; 2], [0.0; 2]));
            ui.add(LevelMeter::stereo(meter_data.0, meter_data.1, colors).height(140.0));
        });

        ui.add_space(2.0);

        // dB readout
        ui.vertical_centered(|ui| {
            let db = if state.session.tracks[track_idx].gain < 1e-10 {
                "-inf".to_string()
            } else {
                format!("{:.1}", 20.0 * state.session.tracks[track_idx].gain.log10())
            };
            ui.label(
                egui::RichText::new(db)
                    .monospace()
                    .size(9.0)
                    .color(colors.text_secondary()),
            );
        });
    });
}

pub mod arrangement;
pub mod browser;
pub mod mixer;
pub mod transport;

use egui::{Color32, CornerRadius, Layout, Ui, vec2};

use crate::state::UiState;
use crate::theme::ThemeColors;
use shruti_session::TransportState;

/// Draw the transport bar at the top of the window.
pub fn transport_bar(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    ui.horizontal(|ui| {
        ui.set_min_height(32.0);
        ui.spacing_mut().item_spacing.x = 4.0;

        // Transport controls
        transport_buttons(ui, state, colors);

        ui.add_space(12.0);
        ui.separator();
        ui.add_space(12.0);

        // Position display
        position_display(ui, state, colors);

        ui.add_space(12.0);
        ui.separator();
        ui.add_space(12.0);

        // Tempo
        tempo_display(ui, state, colors);

        ui.add_space(12.0);
        ui.separator();
        ui.add_space(12.0);

        // Loop toggle
        loop_toggle(ui, state, colors);

        // Right-align session name
        ui.with_layout(Layout::right_to_left(egui::Align::Center), |ui| {
            ui.label(
                egui::RichText::new(&state.session.name)
                    .size(11.0)
                    .color(colors.text_secondary()),
            );
        });
    });
}

fn transport_buttons(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    let btn_size = vec2(28.0, 24.0);
    let is_playing = state.session.transport.state == TransportState::Playing;
    let is_recording = state.recording;

    // Rewind
    if ui
        .add(
            egui::Button::new(egui::RichText::new("⏮").size(14.0))
                .fill(colors.surface())
                .corner_radius(CornerRadius::same(3))
                .min_size(btn_size),
        )
        .clicked()
    {
        state.session.transport.position = 0;
    }

    // Stop
    if ui
        .add(
            egui::Button::new(egui::RichText::new("⏹").size(14.0))
                .fill(colors.surface())
                .corner_radius(CornerRadius::same(3))
                .min_size(btn_size),
        )
        .clicked()
    {
        state.session.transport.state = TransportState::Stopped;
        state.recording = false;
    }

    // Play/Pause
    let play_icon = if is_playing { "⏸" } else { "▶" };
    let play_color = if is_playing {
        colors.transport_active()
    } else {
        colors.surface()
    };
    if ui
        .add(
            egui::Button::new(
                egui::RichText::new(play_icon)
                    .size(14.0)
                    .color(if is_playing {
                        Color32::WHITE
                    } else {
                        colors.text_primary()
                    }),
            )
            .fill(play_color)
            .corner_radius(CornerRadius::same(3))
            .min_size(btn_size),
        )
        .clicked()
    {
        if is_playing {
            state.session.transport.state = TransportState::Paused;
        } else {
            state.session.transport.state = TransportState::Playing;
        }
    }

    // Record
    let rec_color = if is_recording {
        colors.record_red()
    } else {
        colors.surface()
    };
    if ui
        .add(
            egui::Button::new(egui::RichText::new("⏺").size(14.0).color(if is_recording {
                Color32::WHITE
            } else {
                colors.record_red()
            }))
            .fill(rec_color)
            .corner_radius(CornerRadius::same(3))
            .min_size(btn_size),
        )
        .clicked()
    {
        state.recording = !state.recording;
    }
}

fn position_display(ui: &mut Ui, state: &UiState, colors: &ThemeColors) {
    let pos = state.session.transport.position;
    let sr = state.session.sample_rate;
    let bpm = state.session.transport.bpm;

    // Time display (hh:mm:ss.ms)
    let total_secs = pos as f64 / sr as f64;
    let hours = (total_secs / 3600.0) as u32;
    let minutes = ((total_secs % 3600.0) / 60.0) as u32;
    let seconds = total_secs % 60.0;

    let time_str = format!("{hours:02}:{minutes:02}:{seconds:06.3}");

    ui.label(
        egui::RichText::new(time_str)
            .monospace()
            .size(14.0)
            .color(colors.text_primary()),
    );

    ui.add_space(8.0);

    // Bar:Beat display
    let frames_per_beat = (sr as f64 * 60.0) / bpm;
    let total_beats = pos as f64 / frames_per_beat;
    let bar = (total_beats / 4.0).floor() as u32 + 1;
    let beat = (total_beats % 4.0).floor() as u32 + 1;
    let tick = ((total_beats % 1.0) * 960.0) as u32;

    let bar_str = format!("{bar:>3}.{beat}.{tick:03}");

    ui.label(
        egui::RichText::new(bar_str)
            .monospace()
            .size(14.0)
            .color(colors.accent()),
    );
}

fn tempo_display(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    ui.label(
        egui::RichText::new("BPM")
            .size(9.0)
            .color(colors.text_secondary()),
    );

    let mut bpm = state.session.transport.bpm as f32;
    let response = ui.add(
        egui::DragValue::new(&mut bpm)
            .range(20.0..=999.0)
            .speed(0.5)
            .fixed_decimals(1),
    );
    if response.changed() {
        state.session.transport.bpm = bpm as f64;
    }

    // Time signature
    ui.label(
        egui::RichText::new(format!(
            "{}/{}",
            state.session.transport.time_sig_num, state.session.transport.time_sig_den
        ))
        .monospace()
        .size(11.0)
        .color(colors.text_secondary()),
    );
}

fn loop_toggle(ui: &mut Ui, state: &mut UiState, colors: &ThemeColors) {
    let loop_active = state.session.transport.loop_enabled;
    let loop_color = if loop_active {
        colors.accent()
    } else {
        colors.surface()
    };

    if ui
        .add(
            egui::Button::new(egui::RichText::new("⟳").size(14.0).color(if loop_active {
                Color32::WHITE
            } else {
                colors.text_secondary()
            }))
            .fill(loop_color)
            .corner_radius(CornerRadius::same(3))
            .min_size(vec2(28.0, 24.0)),
        )
        .clicked()
    {
        state.session.transport.loop_enabled = !state.session.transport.loop_enabled;
    }
}

use egui::{Rect, Stroke, Ui, pos2};

use crate::theme::ThemeColors;

/// Draw automation points and curves on a lane overlay.
pub fn draw_automation(
    ui: &mut Ui,
    rect: Rect,
    points: &[(f64, f32)], // (frame position, value 0..1)
    scroll_offset: f64,
    pixels_per_frame: f64,
    colors: &ThemeColors,
) {
    if points.is_empty() || rect.width() < 1.0 {
        return;
    }

    let painter = ui.painter_at(rect);

    let frame_to_x =
        |frame: f64| -> f32 { rect.left() + (frame * pixels_per_frame - scroll_offset) as f32 };

    let value_to_y = |value: f32| -> f32 { rect.bottom() - value.clamp(0.0, 1.0) * rect.height() };

    // Draw curve segments between points
    let curve_stroke = Stroke::new(1.5, colors.automation_curve());

    for i in 0..points.len().saturating_sub(1) {
        let (f1, v1) = points[i];
        let (f2, v2) = points[i + 1];

        let x1 = frame_to_x(f1);
        let x2 = frame_to_x(f2);

        // Skip if completely off-screen
        if x2 < rect.left() || x1 > rect.right() {
            continue;
        }

        // Linear interpolation as line segments
        let steps = ((x2 - x1).abs() as usize).clamp(1, 200);
        for s in 0..steps {
            let t1 = s as f32 / steps as f32;
            let t2 = (s + 1) as f32 / steps as f32;
            let y1 = value_to_y(v1 + (v2 - v1) * t1);
            let y2 = value_to_y(v1 + (v2 - v1) * t2);
            let sx1 = x1 + (x2 - x1) * t1;
            let sx2 = x1 + (x2 - x1) * t2;

            painter.line_segment([pos2(sx1, y1), pos2(sx2, y2)], curve_stroke);
        }
    }

    // Draw points
    for &(frame, value) in points {
        let x = frame_to_x(frame);
        let y = value_to_y(value);

        if x >= rect.left() - 5.0 && x <= rect.right() + 5.0 {
            painter.circle_filled(pos2(x, y), 4.0, colors.automation_point());
            painter.circle_stroke(pos2(x, y), 4.0, Stroke::new(1.0, colors.automation_curve()));
        }
    }
}

use egui::{Color32, Rect, Response, Sense, Stroke, Ui, Widget, pos2, vec2};

use crate::theme::ThemeColors;

/// Vertical fader widget for gain control.
pub struct Fader<'a> {
    value: &'a mut f32,
    min_db: f32,
    max_db: f32,
    colors: &'a ThemeColors,
    height: f32,
    width: f32,
}

impl<'a> Fader<'a> {
    pub fn new(value: &'a mut f32, colors: &'a ThemeColors) -> Self {
        Self {
            value,
            min_db: -60.0,
            max_db: 12.0,
            colors,
            height: 160.0,
            width: 24.0,
        }
    }

    pub fn height(mut self, h: f32) -> Self {
        self.height = h;
        self
    }

    fn db_to_normalized(&self, db: f32) -> f32 {
        (db - self.min_db) / (self.max_db - self.min_db)
    }

    fn linear_to_db(linear: f32) -> f32 {
        if linear < 1e-10 {
            -60.0
        } else {
            20.0 * linear.log10()
        }
    }

    fn db_to_linear(db: f32) -> f32 {
        10.0_f32.powf(db / 20.0)
    }
}

impl Widget for Fader<'_> {
    fn ui(self, ui: &mut Ui) -> Response {
        let desired_size = vec2(self.width, self.height);
        let (rect, response) = ui.allocate_exact_size(desired_size, Sense::click_and_drag());

        let current_db = Self::linear_to_db(*self.value);

        // Handle drag interaction
        if response.dragged() {
            let delta_normalized = -response.drag_delta().y / self.height;
            let new_db = (current_db + delta_normalized * (self.max_db - self.min_db))
                .clamp(self.min_db, self.max_db);
            *self.value = Self::db_to_linear(new_db);
        }

        // Double-click to reset to unity
        if response.double_clicked() {
            *self.value = 1.0;
        }

        if ui.is_rect_visible(rect) {
            let painter = ui.painter_at(rect);

            // Track groove
            let groove_x = rect.center().x;
            let groove_rect = Rect::from_min_max(
                pos2(groove_x - 2.0, rect.top() + 4.0),
                pos2(groove_x + 2.0, rect.bottom() - 4.0),
            );
            painter.rect_filled(groove_rect, 2.0, self.colors.bg_primary());

            // Unity (0dB) mark
            let unity_y = rect.bottom() - 4.0 - self.db_to_normalized(0.0) * (self.height - 8.0);
            painter.line_segment(
                [
                    pos2(rect.left() + 2.0, unity_y),
                    pos2(rect.right() - 2.0, unity_y),
                ],
                Stroke::new(1.0, self.colors.text_secondary()),
            );

            // dB scale marks
            for &db in &[-48.0, -24.0, -12.0, -6.0, 6.0] {
                let y = rect.bottom() - 4.0 - self.db_to_normalized(db) * (self.height - 8.0);
                painter.line_segment(
                    [pos2(groove_x - 4.0, y), pos2(groove_x + 4.0, y)],
                    Stroke::new(0.5, self.colors.separator()),
                );
            }

            // Fader cap
            let normalized = self.db_to_normalized(current_db.clamp(self.min_db, self.max_db));
            let fader_y = rect.bottom() - 4.0 - normalized * (self.height - 8.0);
            let cap_rect =
                Rect::from_center_size(pos2(groove_x, fader_y), vec2(self.width - 4.0, 10.0));

            let cap_color = if response.hovered() || response.dragged() {
                self.colors.accent()
            } else {
                self.colors.surface_hover()
            };
            painter.rect_filled(cap_rect, 3.0, cap_color);
            // Center line on cap
            painter.line_segment(
                [
                    pos2(cap_rect.left() + 3.0, fader_y),
                    pos2(cap_rect.right() - 3.0, fader_y),
                ],
                Stroke::new(1.0, Color32::WHITE.linear_multiply(0.6)),
            );

            // Fill below cap
            let fill_rect = Rect::from_min_max(
                pos2(groove_x - 2.0, fader_y),
                pos2(groove_x + 2.0, rect.bottom() - 4.0),
            );
            painter.rect_filled(fill_rect, 1.0, self.colors.accent().linear_multiply(0.5));
        }

        response.on_hover_text(format!("{:.1} dB", Self::linear_to_db(*self.value)))
    }
}

use std::f32::consts::PI;

use egui::{Color32, Response, Sense, Stroke, Ui, Widget, pos2, vec2};

use crate::theme::ThemeColors;

/// Rotary knob widget for pan and other continuous parameters.
pub struct Knob<'a> {
    value: &'a mut f32,
    min: f32,
    max: f32,
    colors: &'a ThemeColors,
    radius: f32,
    label: &'a str,
}

impl<'a> Knob<'a> {
    pub fn new(value: &'a mut f32, min: f32, max: f32, colors: &'a ThemeColors) -> Self {
        Self {
            value,
            min,
            max,
            colors,
            radius: 14.0,
            label: "",
        }
    }

    /// Pan knob: -1.0 to 1.0, center default.
    pub fn pan(value: &'a mut f32, colors: &'a ThemeColors) -> Self {
        Self::new(value, -1.0, 1.0, colors).with_label("Pan")
    }

    pub fn with_label(mut self, label: &'a str) -> Self {
        self.label = label;
        self
    }

    fn normalized(&self) -> f32 {
        (*self.value - self.min) / (self.max - self.min)
    }

    fn set_from_normalized(&mut self, n: f32) {
        *self.value = (n * (self.max - self.min) + self.min).clamp(self.min, self.max);
    }
}

impl Widget for Knob<'_> {
    fn ui(mut self, ui: &mut Ui) -> Response {
        let total_height = self.radius * 2.0 + if self.label.is_empty() { 0.0 } else { 12.0 };
        let desired_size = vec2(self.radius * 2.0, total_height);
        let (rect, response) = ui.allocate_exact_size(desired_size, Sense::click_and_drag());

        // Handle drag
        if response.dragged() {
            let delta = -response.drag_delta().y / 100.0;
            let new_n = (self.normalized() + delta).clamp(0.0, 1.0);
            self.set_from_normalized(new_n);
        }

        // Double-click to reset to center
        if response.double_clicked() {
            *self.value = (self.min + self.max) / 2.0;
        }

        if ui.is_rect_visible(rect) {
            let painter = ui.painter_at(rect);
            let center = pos2(rect.center().x, rect.top() + self.radius);

            // Arc parameters: 135° to 405° (270° sweep)
            let start_angle = 0.75 * PI;
            let sweep = 1.5 * PI;
            let r = self.radius - 2.0;

            // Background arc
            let segments = 32;
            for i in 0..segments {
                let a1 = start_angle + sweep * (i as f32 / segments as f32);
                let a2 = start_angle + sweep * ((i + 1) as f32 / segments as f32);
                painter.line_segment(
                    [
                        pos2(center.x + r * a1.cos(), center.y + r * a1.sin()),
                        pos2(center.x + r * a2.cos(), center.y + r * a2.sin()),
                    ],
                    Stroke::new(3.0, self.colors.bg_primary()),
                );
            }

            // Value arc
            let value_angle = start_angle + sweep * self.normalized();
            let value_segments = (segments as f32 * self.normalized()) as usize;
            let arc_color = if response.hovered() || response.dragged() {
                self.colors.accent_hover()
            } else {
                self.colors.accent()
            };

            for i in 0..value_segments {
                let a1 = start_angle + sweep * (i as f32 / segments as f32);
                let a2 = start_angle + sweep * ((i + 1) as f32 / segments as f32);
                painter.line_segment(
                    [
                        pos2(center.x + r * a1.cos(), center.y + r * a1.sin()),
                        pos2(center.x + r * a2.cos(), center.y + r * a2.sin()),
                    ],
                    Stroke::new(3.0, arc_color),
                );
            }

            // Indicator dot
            let dot_r = r - 4.0;
            let dot_pos = pos2(
                center.x + dot_r * value_angle.cos(),
                center.y + dot_r * value_angle.sin(),
            );
            painter.circle_filled(dot_pos, 2.5, Color32::WHITE);

            // Center circle
            painter.circle_filled(center, 4.0, self.colors.surface());

            // Label
            if !self.label.is_empty() {
                let label_pos = pos2(center.x, rect.bottom() - 2.0);
                painter.text(
                    label_pos,
                    egui::Align2::CENTER_BOTTOM,
                    self.label,
                    egui::FontId::new(9.0, egui::FontFamily::Proportional),
                    self.colors.text_secondary(),
                );
            }
        }

        let display_val = if self.min == -1.0 && self.max == 1.0 {
            if (*self.value).abs() < 0.01 {
                "C".to_string()
            } else if *self.value < 0.0 {
                format!("L{:.0}", (-*self.value * 100.0))
            } else {
                format!("R{:.0}", (*self.value * 100.0))
            }
        } else {
            format!("{:.2}", *self.value)
        };

        response.on_hover_text(display_val)
    }
}

use egui::{Rect, Ui, Widget, pos2, vec2};

use crate::theme::ThemeColors;

/// Vertical level meter with peak + RMS display.
pub struct LevelMeter<'a> {
    peak_l: f32,
    peak_r: f32,
    rms_l: f32,
    rms_r: f32,
    colors: &'a ThemeColors,
    height: f32,
}

impl<'a> LevelMeter<'a> {
    pub fn new(peak_l: f32, peak_r: f32, rms_l: f32, rms_r: f32, colors: &'a ThemeColors) -> Self {
        Self {
            peak_l,
            peak_r,
            rms_l,
            rms_r,
            colors,
            height: 160.0,
        }
    }

    pub fn stereo(peak: [f32; 2], rms: [f32; 2], colors: &'a ThemeColors) -> Self {
        Self::new(peak[0], peak[1], rms[0], rms[1], colors)
    }

    pub fn height(mut self, h: f32) -> Self {
        self.height = h;
        self
    }

    fn db_to_normalized(db: f32) -> f32 {
        // Map -60dB..+6dB to 0..1
        ((db + 60.0) / 66.0).clamp(0.0, 1.0)
    }

    fn linear_to_db(linear: f32) -> f32 {
        if linear < 1e-10 {
            -60.0
        } else {
            20.0 * linear.log10()
        }
    }

    fn meter_color(&self, normalized: f32) -> egui::Color32 {
        if normalized > 0.91 {
            // > -0.5 dB
            self.colors.meter_red()
        } else if normalized > 0.73 {
            // > -6 dB
            self.colors.meter_yellow()
        } else {
            self.colors.meter_green()
        }
    }

    fn draw_bar(&self, ui: &mut Ui, rect: Rect, peak_linear: f32, rms_linear: f32) {
        let painter = ui.painter_at(rect);

        // Background
        painter.rect_filled(rect, 1.0, self.colors.bg_primary());

        let peak_db = Self::linear_to_db(peak_linear);
        let rms_db = Self::linear_to_db(rms_linear);
        let peak_n = Self::db_to_normalized(peak_db);
        let rms_n = Self::db_to_normalized(rms_db);

        // RMS fill (wider, dimmer)
        let rms_h = rms_n * rect.height();
        if rms_h > 0.5 {
            let rms_rect = Rect::from_min_max(
                pos2(rect.left(), rect.bottom() - rms_h),
                rect.right_bottom(),
            );
            let color = self.meter_color(rms_n).linear_multiply(0.5);
            painter.rect_filled(rms_rect, 0.0, color);
        }

        // Peak fill (brighter, on top)
        let peak_h = peak_n * rect.height();
        if peak_h > 0.5 {
            let peak_rect = Rect::from_min_max(
                pos2(rect.left() + 1.0, rect.bottom() - peak_h),
                pos2(rect.right() - 1.0, rect.bottom()),
            );
            let color = self.meter_color(peak_n);
            painter.rect_filled(peak_rect, 0.0, color);
        }

        // Peak hold line
        if peak_n > 0.01 {
            let y = rect.bottom() - peak_n * rect.height();
            painter.line_segment(
                [pos2(rect.left(), y), pos2(rect.right(), y)],
                egui::Stroke::new(1.0, self.meter_color(peak_n)),
            );
        }
    }
}

impl Widget for LevelMeter<'_> {
    fn ui(self, ui: &mut Ui) -> egui::Response {
        let bar_width = 6.0;
        let gap = 2.0;
        let total_width = bar_width * 2.0 + gap;
        let desired_size = vec2(total_width, self.height);
        let (rect, response) = ui.allocate_exact_size(desired_size, egui::Sense::hover());

        if ui.is_rect_visible(rect) {
            let left_rect = Rect::from_min_size(rect.min, vec2(bar_width, self.height));
            let right_rect = Rect::from_min_size(
                pos2(rect.left() + bar_width + gap, rect.top()),
                vec2(bar_width, self.height),
            );

            self.draw_bar(ui, left_rect, self.peak_l, self.rms_l);
            self.draw_bar(ui, right_rect, self.peak_r, self.rms_r);
        }

        response
    }
}

