/// A plugin slot in a channel strip or track inspector.
pub struct PluginSlotState {
    pub name: String,
    pub bypassed: bool,
}

pub struct PluginSlotResponse {
    pub clicked: bool,
    pub bypass_toggled: bool,
}

/// Draw a plugin slot widget.
pub fn plugin_slot_ui(
    ui: &mut Ui,
    state: &PluginSlotState,
    colors: &ThemeColors,
) -> PluginSlotResponse {
    let mut response = PluginSlotResponse {
        clicked: false,
        bypass_toggled: false,
    };

    ui.horizontal(|ui| {
        // Bypass indicator
        let bypass_color = if state.bypassed {
            colors.mute_orange()
        } else {
            colors.transport_active()
        };
        let bypass_btn = ui.add(
            egui::Button::new(
                egui::RichText::new(if state.bypassed { "○" } else { "●" })
                    .size(10.0)
                    .color(bypass_color),
            )
            .fill(colors.surface())
            .corner_radius(CornerRadius::same(2))
            .min_size(vec2(16.0, 16.0)),
        );
        if bypass_btn.clicked() {
            response.bypass_toggled = true;
        }

        // Plugin name button
        let name_btn = ui.add(
            egui::Button::new(egui::RichText::new(&state.name).size(10.0).color(
                if state.bypassed {
                    colors.text_secondary()
                } else {
                    colors.text_primary()
                },
            ))
            .fill(colors.surface())
            .corner_radius(CornerRadius::same(2))
            .min_size(vec2(80.0, 16.0)),
        );
        if name_btn.clicked() {
            response.clicked = true;
        }
    });

    response
}

use egui::{CornerRadius, Rect, Stroke, Ui, pos2, vec2};

use crate::theme::ThemeColors;
use crate::widgets::track_header::track_color;

/// Draw a region/clip rectangle on the timeline.
pub fn draw_region(
    ui: &mut Ui,
    rect: Rect,
    name: &str,
    color_index: usize,
    selected: bool,
    colors: &ThemeColors,
) {
    if rect.width() < 1.0 {
        return;
    }

    let painter = ui.painter_at(rect);
    let rounding = CornerRadius::same(3);

    // Region background
    let base_color = track_color(color_index);
    let bg = if selected {
        colors.region_selected()
    } else {
        base_color.linear_multiply(0.3)
    };
    painter.rect_filled(rect, rounding, bg);

    // Border
    let border_color = if selected {
        colors.accent()
    } else {
        base_color.linear_multiply(0.6)
    };
    painter.rect_stroke(
        rect,
        rounding,
        Stroke::new(1.0, border_color),
        egui::StrokeKind::Outside,
    );

    // Top accent bar
    let top_bar = Rect::from_min_size(rect.min, vec2(rect.width(), 2.0));
    painter.rect_filled(top_bar, CornerRadius::ZERO, base_color.linear_multiply(0.7));

    // Name label (clipped to region bounds)
    if rect.width() > 30.0 {
        let text_rect = rect.shrink2(vec2(4.0, 2.0));
        let text_pos = pos2(text_rect.left(), text_rect.top() + 2.0);
        painter.text(
            text_pos,
            egui::Align2::LEFT_TOP,
            name,
            egui::FontId::new(9.0, egui::FontFamily::Proportional),
            colors.text_primary(),
        );
    }
}

use egui::{Rect, Stroke, Ui, pos2};

use crate::theme::ThemeColors;

/// Draw a timeline ruler showing bars/beats or time.
pub fn draw_ruler(
    ui: &mut Ui,
    rect: Rect,
    scroll_offset: f64,
    pixels_per_frame: f64,
    sample_rate: u32,
    bpm: f64,
    colors: &ThemeColors,
) {
    let painter = ui.painter_at(rect);

    // Background
    painter.rect_filled(rect, 0.0, colors.bg_secondary());

    // Bottom border
    painter.line_segment(
        [rect.left_bottom(), rect.right_bottom()],
        Stroke::new(1.0, colors.separator()),
    );

    let frames_per_beat = (sample_rate as f64 * 60.0) / bpm;
    let frames_per_bar = frames_per_beat * 4.0; // Assuming 4/4
    let pixels_per_bar = frames_per_bar * pixels_per_frame;

    // Determine tick spacing based on zoom
    let (major_interval, minor_interval, label_fn): (f64, f64, Box<dyn Fn(i64) -> String>) =
        if pixels_per_bar > 200.0 {
            // Show beats
            (
                frames_per_bar,
                frames_per_beat,
                Box::new(move |frame: i64| {
                    let bar = (frame as f64 / frames_per_bar).floor() as i64 + 1;
                    format!("{bar}")
                }),
            )
        } else if pixels_per_bar > 40.0 {
            // Show bars
            (
                frames_per_bar,
                frames_per_bar,
                Box::new(move |frame: i64| {
                    let bar = (frame as f64 / frames_per_bar).floor() as i64 + 1;
                    format!("{bar}")
                }),
            )
        } else {
            // Show every N bars
            let bar_skip = (80.0 / pixels_per_bar).ceil() as i64;
            let major = frames_per_bar * bar_skip as f64;
            (
                major,
                frames_per_bar,
                Box::new(move |frame: i64| {
                    let bar = (frame as f64 / frames_per_bar).floor() as i64 + 1;
                    format!("{bar}")
                }),
            )
        };

    // Visible frame range
    let start_frame = (scroll_offset / pixels_per_frame) as i64;
    let end_frame = start_frame + (rect.width() as f64 / pixels_per_frame) as i64;

    // Minor ticks
    let minor_start = (start_frame as f64 / minor_interval).floor() as i64;
    let minor_end = (end_frame as f64 / minor_interval).ceil() as i64;

    for i in minor_start..=minor_end {
        let frame = (i as f64 * minor_interval) as i64;
        let x = rect.left() + (frame as f64 * pixels_per_frame - scroll_offset) as f32;
        if x >= rect.left() && x <= rect.right() {
            painter.line_segment(
                [pos2(x, rect.bottom() - 4.0), pos2(x, rect.bottom())],
                Stroke::new(0.5, colors.text_secondary()),
            );
        }
    }

    // Major ticks with labels
    let major_start = (start_frame as f64 / major_interval).floor() as i64;
    let major_end = (end_frame as f64 / major_interval).ceil() as i64;

    for i in major_start..=major_end {
        let frame = (i as f64 * major_interval) as i64;
        let x = rect.left() + (frame as f64 * pixels_per_frame - scroll_offset) as f32;
        if x >= rect.left() && x <= rect.right() {
            painter.line_segment(
                [pos2(x, rect.bottom() - 10.0), pos2(x, rect.bottom())],
                Stroke::new(1.0, colors.text_secondary()),
            );

            let label = label_fn(frame);
            painter.text(
                pos2(x + 3.0, rect.top() + 2.0),
                egui::Align2::LEFT_TOP,
                label,
                egui::FontId::new(9.0, egui::FontFamily::Proportional),
                colors.text_secondary(),
            );
        }
    }
}

use egui::{Color32, CornerRadius, Layout, Ui, vec2};

use crate::theme::ThemeColors;

/// Track header state for the UI.
pub struct TrackHeaderState {
    pub name: String,
    pub muted: bool,
    pub solo: bool,
    pub armed: bool,
    pub selected: bool,
    pub color_index: usize,
}

/// Track color palette (10 colors, cycling).
const TRACK_COLORS: [Color32; 10] = [
    Color32::from_rgb(70, 130, 210),  // Blue
    Color32::from_rgb(80, 180, 100),  // Green
    Color32::from_rgb(200, 100, 60),  // Orange
    Color32::from_rgb(170, 80, 190),  // Purple
    Color32::from_rgb(200, 180, 50),  // Yellow
    Color32::from_rgb(80, 190, 190),  // Cyan
    Color32::from_rgb(210, 80, 100),  // Red
    Color32::from_rgb(130, 180, 70),  // Lime
    Color32::from_rgb(180, 130, 80),  // Tan
    Color32::from_rgb(120, 100, 200), // Indigo
];

pub fn track_color(index: usize) -> Color32 {
    TRACK_COLORS[index % TRACK_COLORS.len()]
}

/// Draw a track header, returning which buttons were clicked.
pub struct TrackHeaderResponse {
    pub mute_clicked: bool,
    pub solo_clicked: bool,
    pub arm_clicked: bool,
    pub selected: bool,
}

pub fn track_header_ui(
    ui: &mut Ui,
    state: &TrackHeaderState,
    colors: &ThemeColors,
    width: f32,
) -> TrackHeaderResponse {
    let mut response = TrackHeaderResponse {
        mute_clicked: false,
        solo_clicked: false,
        arm_clicked: false,
        selected: false,
    };

    let height = 60.0;
    let (rect, click_response) = ui.allocate_exact_size(vec2(width, height), egui::Sense::click());

    if click_response.clicked() {
        response.selected = true;
    }

    if ui.is_rect_visible(rect) {
        let painter = ui.painter_at(rect);

        // Background
        let bg = if state.selected {
            colors.accent().linear_multiply(0.15)
        } else {
            colors.track_header()
        };
        painter.rect_filled(rect, 0.0, bg);

        // Color strip on left edge
        let strip_rect = rect.with_max_x(rect.left() + 4.0);
        painter.rect_filled(strip_rect, 0.0, track_color(state.color_index));

        // Bottom separator
        painter.line_segment(
            [rect.left_bottom(), rect.right_bottom()],
            egui::Stroke::new(0.5, colors.separator()),
        );
    }

    // UI inside the header
    let inner_rect = rect.shrink2(vec2(8.0, 4.0));
    let mut child_ui = ui.new_child(egui::UiBuilder::new().max_rect(inner_rect));

    child_ui.with_layout(Layout::top_down(egui::Align::LEFT), |ui| {
        // Track name
        ui.label(
            egui::RichText::new(&state.name)
                .size(11.0)
                .color(colors.text_primary()),
        );

        ui.add_space(2.0);

        // M S R buttons
        ui.horizontal(|ui| {
            ui.spacing_mut().item_spacing.x = 2.0;

            // Mute button
            let mute_color = if state.muted {
                colors.mute_orange()
            } else {
                colors.surface()
            };
            let mute_btn = ui.add(
                egui::Button::new(egui::RichText::new("M").size(10.0).color(if state.muted {
                    Color32::WHITE
                } else {
                    colors.text_secondary()
                }))
                .fill(mute_color)
                .corner_radius(CornerRadius::same(2))
                .min_size(vec2(20.0, 16.0)),
            );
            if mute_btn.clicked() {
                response.mute_clicked = true;
            }

            // Solo button
            let solo_color = if state.solo {
                colors.solo_yellow()
            } else {
                colors.surface()
            };
            let solo_btn = ui.add(
                egui::Button::new(egui::RichText::new("S").size(10.0).color(if state.solo {
                    Color32::BLACK
                } else {
                    colors.text_secondary()
                }))
                .fill(solo_color)
                .corner_radius(CornerRadius::same(2))
                .min_size(vec2(20.0, 16.0)),
            );
            if solo_btn.clicked() {
                response.solo_clicked = true;
            }

            // Record arm button
            let arm_color = if state.armed {
                colors.record_red()
            } else {
                colors.surface()
            };
            let arm_btn = ui.add(
                egui::Button::new(egui::RichText::new("R").size(10.0).color(if state.armed {
                    Color32::WHITE
                } else {
                    colors.text_secondary()
                }))
                .fill(arm_color)
                .corner_radius(CornerRadius::same(2))
                .min_size(vec2(20.0, 16.0)),
            );
            if arm_btn.clicked() {
                response.arm_clicked = true;
            }
        });
    });

    response
}

use egui::{Color32, Rect, Stroke, Ui, pos2};

use crate::theme::ThemeColors;

/// Pre-computed waveform peak data for display at different zoom levels.
#[derive(Debug, Clone)]
pub struct WaveformPeaks {
    /// Min/max pairs per pixel column at various resolutions.
    /// Index 0 = finest (1:1), each subsequent level halves resolution.
    pub levels: Vec<Vec<(f32, f32)>>,
}

impl WaveformPeaks {
    /// Compute mipmap-style peak data from raw samples.
    pub fn from_samples(samples: &[f32], channel: usize, channels: usize) -> Self {
        // Extract mono channel
        let mono: Vec<f32> = samples
            .iter()
            .skip(channel)
            .step_by(channels)
            .copied()
            .collect();

        let mut levels = Vec::new();

        // Level 0: raw peaks per sample
        let level0: Vec<(f32, f32)> = mono.iter().map(|&s| (s.min(0.0), s.max(0.0))).collect();
        levels.push(level0);

        // Generate mipmap levels (each halving)
        let mut current = &levels[0];
        for _ in 0..12 {
            if current.len() <= 1 {
                break;
            }
            let next: Vec<(f32, f32)> = current
                .chunks(2)
                .map(|chunk| {
                    let min = chunk.iter().map(|p| p.0).fold(f32::MAX, f32::min);
                    let max = chunk.iter().map(|p| p.1).fold(f32::MIN, f32::max);
                    (min, max)
                })
                .collect();
            levels.push(next);
            current = levels.last().unwrap();
        }

        Self { levels }
    }

    /// Get the best mipmap level for the given samples-per-pixel ratio.
    pub fn peaks_for_zoom(&self, samples_per_pixel: f32) -> &[(f32, f32)] {
        let level = (samples_per_pixel.log2().max(0.0)) as usize;
        let idx = level.min(self.levels.len() - 1);
        &self.levels[idx]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn from_samples_mono_basic() {
        // Mono signal: [0.5, -0.3, 0.8, -0.1]
        let samples = vec![0.5_f32, -0.3, 0.8, -0.1];
        let peaks = WaveformPeaks::from_samples(&samples, 0, 1);

        assert!(!peaks.levels.is_empty());
        // Level 0 should have 4 entries (one per sample)
        assert_eq!(peaks.levels[0].len(), 4);

        // Positive samples: min=0, max=sample
        assert_eq!(peaks.levels[0][0], (0.0, 0.5));
        // Negative samples: min=sample, max=0
        assert_eq!(peaks.levels[0][1], (-0.3, 0.0));
        assert_eq!(peaks.levels[0][2], (0.0, 0.8));
        assert_eq!(peaks.levels[0][3], (-0.1, 0.0));
    }

    #[test]
    fn from_samples_stereo_extracts_channel() {
        // Interleaved stereo: L=0.5, R=-0.5, L=0.3, R=-0.3
        let samples = vec![0.5_f32, -0.5, 0.3, -0.3];
        let left = WaveformPeaks::from_samples(&samples, 0, 2);
        let right = WaveformPeaks::from_samples(&samples, 1, 2);

        assert_eq!(left.levels[0].len(), 2);
        assert_eq!(left.levels[0][0], (0.0, 0.5));
        assert_eq!(left.levels[0][1], (0.0, 0.3));

        assert_eq!(right.levels[0].len(), 2);
        assert_eq!(right.levels[0][0], (-0.5, 0.0));
        assert_eq!(right.levels[0][1], (-0.3, 0.0));
    }

    #[test]
    fn mipmap_levels_halve_in_size() {
        let samples: Vec<f32> = (0..64).map(|i| (i as f32 / 32.0) - 1.0).collect();
        let peaks = WaveformPeaks::from_samples(&samples, 0, 1);

        assert!(peaks.levels.len() >= 3);
        assert_eq!(peaks.levels[0].len(), 64);
        assert_eq!(peaks.levels[1].len(), 32);
        assert_eq!(peaks.levels[2].len(), 16);

        // Each subsequent level should be half
        for i in 1..peaks.levels.len() {
            let expected = (peaks.levels[i - 1].len() + 1) / 2;
            assert_eq!(peaks.levels[i].len(), expected);
        }
    }

    #[test]
    fn mipmap_preserves_min_max() {
        // Two samples: 0.5 and -0.3; level 1 should merge them
        let samples = vec![0.5_f32, -0.3];
        let peaks = WaveformPeaks::from_samples(&samples, 0, 1);

        assert!(peaks.levels.len() >= 2);
        // Level 1 merges the two: min of (0.0, -0.3) = -0.3, max of (0.5, 0.0) = 0.5
        assert_eq!(peaks.levels[1][0], (-0.3, 0.5));
    }

    #[test]
    fn peaks_for_zoom_level_0() {
        let samples: Vec<f32> = (0..16).map(|i| (i as f32) / 16.0).collect();
        let peaks = WaveformPeaks::from_samples(&samples, 0, 1);

        // samples_per_pixel = 1.0 => log2(1) = 0 => level 0
        let data = peaks.peaks_for_zoom(1.0);
        assert_eq!(data.len(), 16);
    }

    #[test]
    fn peaks_for_zoom_higher_levels() {
        let samples: Vec<f32> = (0..64).map(|i| (i as f32) / 64.0).collect();
        let peaks = WaveformPeaks::from_samples(&samples, 0, 1);

        // samples_per_pixel = 2.0 => log2(2) = 1 => level 1
        let level1 = peaks.peaks_for_zoom(2.0);
        assert_eq!(level1.len(), 32);

        // samples_per_pixel = 4.0 => log2(4) = 2 => level 2
        let level2 = peaks.peaks_for_zoom(4.0);
        assert_eq!(level2.len(), 16);
    }

    #[test]
    fn peaks_for_zoom_clamps_to_max_level() {
        let samples = vec![0.5_f32; 4];
        let peaks = WaveformPeaks::from_samples(&samples, 0, 1);
        let max_level = peaks.levels.len() - 1;

        // Very high zoom should clamp to last level
        let data = peaks.peaks_for_zoom(100000.0);
        assert_eq!(data.len(), peaks.levels[max_level].len());
    }

    #[test]
    fn empty_samples() {
        let peaks = WaveformPeaks::from_samples(&[], 0, 1);
        assert_eq!(peaks.levels.len(), 1);
        assert!(peaks.levels[0].is_empty());
    }

    #[test]
    fn single_sample() {
        let peaks = WaveformPeaks::from_samples(&[0.7], 0, 1);
        assert_eq!(peaks.levels[0].len(), 1);
        assert_eq!(peaks.levels[0][0], (0.0, 0.7));
    }
}

/// Draw a waveform into a given rectangle.
pub fn draw_waveform(
    ui: &mut Ui,
    rect: Rect,
    peaks: &WaveformPeaks,
    start_sample: usize,
    samples_per_pixel: f32,
    colors: &ThemeColors,
) {
    if rect.width() < 1.0 || rect.height() < 1.0 || peaks.levels.is_empty() {
        return;
    }

    let painter = ui.painter_at(rect);
    let center_y = rect.center().y;
    let half_h = rect.height() / 2.0;

    let peak_data = peaks.peaks_for_zoom(samples_per_pixel);
    let zoom_divisor = (samples_per_pixel as usize).max(1);

    let fill_color = colors.waveform();
    let outline_color = colors.waveform_outline();

    let width = rect.width() as usize;
    for px in 0..width {
        let sample_idx = start_sample + px * zoom_divisor;
        let peak_idx = sample_idx / zoom_divisor.max(1);

        if peak_idx >= peak_data.len() {
            break;
        }

        let (min, max) = peak_data[peak_idx.min(peak_data.len() - 1)];
        let x = rect.left() + px as f32;
        let y_top = center_y - max * half_h;
        let y_bot = center_y - min * half_h;

        // Fill
        if (y_bot - y_top).abs() > 0.5 {
            painter.line_segment(
                [pos2(x, y_top), pos2(x, y_bot)],
                Stroke::new(1.0, fill_color),
            );
        } else {
            // Single pixel dot
            painter.line_segment(
                [pos2(x, center_y - 0.5), pos2(x, center_y + 0.5)],
                Stroke::new(1.0, fill_color),
            );
        }

        // Outline at peaks
        painter.circle_filled(pos2(x, y_top), 0.3, outline_color);
        painter.circle_filled(pos2(x, y_bot), 0.3, outline_color);
    }

    // Center line
    painter.line_segment(
        [pos2(rect.left(), center_y), pos2(rect.right(), center_y)],
        Stroke::new(0.5, Color32::from_white_alpha(30)),
    );
}

use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::sync::atomic::{AtomicBool, Ordering};

use clap::Parser;
use shruti_dsp::io::{read_audio_file, write_wav_file};
use shruti_dsp::{AudioBuffer, AudioFormat};
use shruti_engine::backend::{AudioHost, CpalBackend};
use shruti_engine::graph::{FilePlayerNode, Graph, GraphProcessor, NodeId};

#[derive(Parser)]
#[command(
    name = "shruti-play",
    about = "Shruti audio playback and recording tool"
)]
struct Cli {
    /// Audio file to play (WAV or FLAC)
    file: Option<PathBuf>,

    /// Record from default input device to this WAV file
    #[arg(long)]
    record: Option<PathBuf>,

    /// Audio device name (uses default if not specified)
    #[arg(long)]
    device: Option<String>,

    /// Buffer size in frames
    #[arg(long, default_value = "256")]
    buffer_size: u32,

    /// Sample rate
    #[arg(long, default_value = "48000")]
    sample_rate: u32,

    /// List available audio devices
    #[arg(long)]
    list_devices: bool,

    /// Loop playback
    #[arg(long, short)]
    r#loop: bool,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cli = Cli::parse();
    let backend = CpalBackend::new();

    if cli.list_devices {
        println!("Output devices:");
        for dev in backend.output_devices() {
            let marker = if dev.is_default { " (default)" } else { "" };
            println!("  {}{}", dev.name, marker);
        }
        println!("\nInput devices:");
        for dev in backend.input_devices() {
            let marker = if dev.is_default { " (default)" } else { "" };
            println!("  {}{}", dev.name, marker);
        }
        return Ok(());
    }

    if let Some(output_path) = cli.record {
        return record(
            &backend,
            cli.device.as_ref(),
            cli.buffer_size,
            cli.sample_rate,
            &output_path,
        );
    }

    let file = cli
        .file
        .ok_or("provide a file to play, or use --record <path>")?;
    play(
        &backend,
        cli.device.as_ref(),
        cli.buffer_size,
        &file,
        cli.r#loop,
    )
}

fn play(
    backend: &CpalBackend,
    device: Option<&String>,
    buffer_size: u32,
    path: &Path,
    looping: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    let (buffer, file_format) = read_audio_file(path)?;
    let frames = buffer.frames();
    let channels = buffer.channels();
    let duration_secs = frames as f64 / file_format.sample_rate as f64;

    println!(
        "Playing: {} ({:.1}s, {}Hz, {}ch)",
        path.display(),
        duration_secs,
        file_format.sample_rate,
        channels,
    );

    let format = AudioFormat::new(file_format.sample_rate, channels, buffer_size);

    let player_id = NodeId::next();
    let mut graph = Graph::new();
    graph.add_node(player_id, Box::new(FilePlayerNode::new(buffer, looping)));
    let plan = graph.compile()?;

    let mut processor = GraphProcessor::new();
    let handle = processor.swap_handle();
    handle.swap(plan);

    let finished = Arc::new(AtomicBool::new(false));
    let finished_cb = Arc::clone(&finished);

    // Ctrl+C handler
    let ctrlc_flag = Arc::clone(&finished);
    ctrlc_handler(ctrlc_flag);

    let stream = backend.open_output_stream(
        device.map(|s| s.as_str()),
        format,
        Box::new(move |data: &mut [f32]| {
            let buf_frames = data.len() as u32 / channels as u32;
            processor.process(data, channels, buf_frames);

            if processor.is_finished() {
                finished_cb.store(true, Ordering::Relaxed);
            }
        }),
    )?;

    stream.start()?;

    while !finished.load(Ordering::Relaxed) {
        std::thread::sleep(std::time::Duration::from_millis(50));
    }

    stream.stop()?;
    println!("Done.");
    Ok(())
}

fn record(
    backend: &CpalBackend,
    device: Option<&String>,
    buffer_size: u32,
    sample_rate: u32,
    output_path: &Path,
) -> Result<(), Box<dyn std::error::Error>> {
    let channels = 2u16;
    let format = AudioFormat::new(sample_rate, channels, buffer_size);

    println!(
        "Recording to: {} ({}Hz, {}ch) — press Ctrl+C to stop",
        output_path.display(),
        sample_rate,
        channels,
    );

    // Use a ring buffer: RT callback pushes, main thread drains
    let capacity = sample_rate as usize * channels as usize * 10;
    let (mut producer, mut consumer) = rtrb::RingBuffer::new(capacity);

    let stop = Arc::new(AtomicBool::new(false));
    ctrlc_handler(Arc::clone(&stop));

    let stream = backend.open_input_stream(
        device.map(|s| s.as_str()),
        format,
        Box::new(move |data: &[f32]| {
            for &sample in data {
                let _ = producer.push(sample);
            }
        }),
    )?;

    stream.start()?;

    let mut all_samples: Vec<f32> = Vec::new();

    while !stop.load(Ordering::Relaxed) {
        // Drain available samples from the ring buffer
        while let Ok(sample) = consumer.pop() {
            all_samples.push(sample);
        }
        std::thread::sleep(std::time::Duration::from_millis(10));
    }

    stream.stop()?;

    // Final drain
    while let Ok(sample) = consumer.pop() {
        all_samples.push(sample);
    }

    println!("Recording stopped. Saving...");

    let buffer = AudioBuffer::from_interleaved(all_samples, channels);
    let audio_format = AudioFormat::new(sample_rate, channels, 0);
    write_wav_file(output_path, &buffer, &audio_format)?;

    println!("Saved to: {}", output_path.display());
    Ok(())
}

fn ctrlc_handler(_flag: Arc<AtomicBool>) {
    // TODO: Add signal-hook crate for proper Ctrl+C handling
    // For now, Ctrl+C terminates the process directly
}

use clap::Parser;

#[derive(Parser)]
#[command(
    name = "shruti",
    version,
    about = "Shruti — A Rust-native Digital Audio Workstation"
)]
struct Cli {
    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(clap::Subcommand)]
enum Commands {
    /// Show version info
    Version,
    /// List audio devices
    Devices,
    /// Launch the GUI (default)
    Gui {
        /// Session file to open
        #[arg(short, long)]
        session: Option<String>,
        /// Theme file to load (JSON)
        #[arg(short, long)]
        theme: Option<String>,
    },
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Some(Commands::Version) => {
            println!("shruti v{}", env!("CARGO_PKG_VERSION"));
        }
        Some(Commands::Devices) => {
            use shruti_engine::backend::{AudioHost, CpalBackend};
            let backend = CpalBackend::new();

            println!("Output devices:");
            for dev in backend.output_devices() {
                let marker = if dev.is_default { " (default)" } else { "" };
                println!("  {}{}", dev.name, marker);
            }
            println!("\nInput devices:");
            for dev in backend.input_devices() {
                let marker = if dev.is_default { " (default)" } else { "" };
                println!("  {}{}", dev.name, marker);
            }
        }
        Some(Commands::Gui { session: _, theme }) => {
            let session = shruti_session::Session::new("Untitled", 48000, 256);

            let result = if let Some(ref theme_path) = theme {
                match shruti_ui::Theme::load(std::path::Path::new(theme_path)) {
                    Ok(t) => shruti_ui::run_with_theme(session, t),
                    Err(e) => {
                        eprintln!("Warning: failed to load theme: {e}. Using default.");
                        shruti_ui::run(session)
                    }
                }
            } else {
                shruti_ui::run(session)
            };

            if let Err(e) = result {
                eprintln!("Error: {e}");
                std::process::exit(1);
            }
        }
        None => {
            // Default: launch GUI with new session
            let session = shruti_session::Session::new("Untitled", 48000, 256);
            if let Err(e) = shruti_ui::run(session) {
                eprintln!("Error: {e}");
                std::process::exit(1);
            }
        }
    }
}
